const GEMINI_API_KEY = "AIzaSyAQw8xdkGilkHfdanuW2l25K0RePuVnRkc";
const GEMINI_MODEL   = "gemini-2.5-flash-lite-preview-06-17"; // Updated: 2.0 band hoga June 2026
const GEMINI_URL     = `https://generativelanguage.googleapis.com/v1beta/models/${GEMINI_MODEL}:generateContent?key=${GEMINI_API_KEY}`;

async function callGemini(systemPrompt, userMessage) {
  try {
    if (!GEMINI_API_KEY || GEMINI_API_KEY === "APNI_API_KEY_YAHAN_DAALO") {
      return "[icon] ️ AI API Key not set. Please add GEMINI_API_KEY in billing.html (free from aistudio.google.com)";
    }
    const now = Date.now();
    const lastCall = window._siploraLastCall || 0;
    if (now - lastCall < 3000) {
      await new Promise(r => setTimeout(r, 3000 - (now - lastCall)));
    }
    window._siploraLastCall = Date.now();

    const response = await fetch(GEMINI_URL, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        system_instruction: { parts: [{ text: systemPrompt }] },
        contents: [{ role: "user", parts: [{ text: userMessage }] }],
        generationConfig: { maxOutputTokens: 1024, temperature: 0.7 }
      })
    });
    if (!response.ok) {
      const err = await response.json().catch(()=>({}));
      console.error("Gemini API error:", err);
      const errMsg = err?.error?.message || 'Unknown error';
      const errCode = err?.error?.code || response.status;
      if (errCode === 429) return "[icon] Please try again in a moment — API limit temporarily reached. (Wait 1-2 minutes)";
      if (errCode === 400) return "[icon] API Key is invalid or expired. Get a new key from Google AI Studio (aistudio.google.com) and update GEMINI_API_KEY.";
      if (errCode === 403) return "[icon] API access denied. Is your key correct? Check on aistudio.google.com.";
      return `${_si(0)} AI Error ${errCode}: ${errMsg}. Please try a new API key.`;
    }
    const data = await response.json();
    return data.candidates?.[0]?.content?.parts?.[0]?.text || "[icon] No response from AI. Please try again.";
  } catch(e) {
    console.error("Gemini error:", e);
    if (e.message && e.message.includes('fetch')) {
      return "[icon] Network error — Please check your internet connection. If internet is fine, there may be a CORS issue — open the file from a local server (use VS Code Live Server).";
    }
    return "[icon] Connection error. Check your internet and browser console (F12).";
  }
}

window.getLiveRestaurantData = function() {
  try {
    const orders    = (window.getLiveOrders    ? window.getLiveOrders()    : null) || (()=>{try{return JSON.parse(localStorage.getItem(window._sipKey('lum_orders'))||'[]');}catch(e){return[];}})();
    const menu      = (()=>{try{return JSON.parse(localStorage.getItem(window._sipKey('lum_menu'))||'[]');}catch(e){return[];}})();
    const stock     = (window.getLiveStock     ? window.getLiveStock()     : null) || (()=>{try{return JSON.parse(localStorage.getItem(window._sipKey('lum_stock'))||'[]');}catch(e){return[];}})();
    const customers = (window.getLiveCustomers ? window.getLiveCustomers() : null) || (()=>{try{return JSON.parse(localStorage.getItem(window._sipKey('lum_customers'))||'[]');}catch(e){return[];}})();
    const tasks     = (()=>{try{return JSON.parse(localStorage.getItem(window._sipKey('lum_tasks'))||'[]');}catch(e){return[];}})();
    const staff     = (window.getLiveStaff     ? window.getLiveStaff()     : null) || (()=>{try{return JSON.parse(localStorage.getItem(window._sipKey('smStaff'))||'[]');}catch(e){return[];}})();
    const today     = new Date().toDateString();
    const todayOrders  = orders.filter(o => {
      const t=o.createdAt||o.timestamp||o.time||o.date;
      if(!t) return false;
      try{ const d=(typeof t==='object'&&t.seconds)?new Date(t.seconds*1000):new Date(t); return d.toDateString()===today; }catch(e){return false;}
    });
    const todayRevenue = todayOrders.filter(o=>o.status==='paid'||o.status==='completed').reduce((s,o) => s + (o.totalAmount||o.totalBilled||o.total||o.amount||0), 0);
    const lowStock     = stock.filter(i => Number(i.qty||i.stock||0) <= Number(i.alert||i.minQty||10));
    const todayBirthdays = customers.filter(c => {
      if (!c.bday) return false;
      const t  = new Date();
      const md = String(t.getMonth()+1).padStart(2,'0') + '-' + String(t.getDate()).padStart(2,'0');
      return c.bday.slice(5) === md;
    });
    return `
Restaurant: Siplora | Date: ${new Date().toLocaleDateString('en-IN')}
Today Revenue: ₹${todayRevenue.toLocaleString('en-IN')}
Today Orders: ${todayOrders.length}
Total Orders (All Time): ${orders.length}
Total Menu Items: ${menu.length}
Staff Count: ${staff.length} | Active Staff: ${staff.filter(s=>(s.status||'').toLowerCase()==='active').length}
Low Stock Items: ${lowStock.map(i=>i.name+'('+(i.qty||i.stock||0)+' '+(i.unit||'')+')').join(', ')||'None'}
Today Birthdays: ${todayBirthdays.map(c=>c.name).join(', ')||'None'}
Pending Tasks: ${tasks.filter(t=>t.status==='Pending').length}
Total Customers: ${customers.length}
    `.trim();
  } catch(e) { return 'Restaurant data available'; }
};

