        +'<div class="sbox"><div class="sbox-label">Grand Total</div><div class="sbox-val" style="color:#1a6e3a">₹'+gtt.toLocaleString('en-IN')+'</div></div>'
      +'</div>'
      +'<table>'
        +'<thead><tr>'
          +'<th>Bill No.</th><th>Customer</th><th>Type</th><th class="num">Trans.</th>'
          +'<th class="num">Taxable</th><th class="num">Rate</th>'
          +'<th class="num">CGST</th><th class="num">SGST</th><th class="num">IGST</th>'
          +'<th class="num">Grand Total</th>'
        +'</tr></thead>'
        +'<tbody>'+dayRows+'</tbody>'
        +'<tfoot><tr class="grand-row">'
          +'<td colspan="4">GRAND TOTAL</td>'
          +'<td class="num bold">₹'+gtax.toLocaleString('en-IN')+'</td>'
          +'<td></td>'
          +'<td class="num bold" style="color:#c0701e">₹'+gcg.toLocaleString('en-IN')+'</td>'
          +'<td class="num bold" style="color:#1a6fa0">₹'+gsg.toLocaleString('en-IN')+'</td>'
