let manualItemCount=1;
function addItemRow(){
  manualItemCount++;
  const c=document.getElementById('m-items-container');
  const div=document.createElement('div');
  div.className='form-grid-3';
  div.style.marginBottom='8px';
  div.innerHTML=`<div class="form-group" style="margin:0"><input class="form-input m-dish" placeholder="Dish name" oninput="calcManualBill()"/></div><div class="form-group" style="margin:0"><input class="form-input m-qty" type="number" placeholder="Qty" min="1" value="1" oninput="calcManualBill()"/></div><div class="form-group" style="margin:0"><input class="form-input m-price" type="number" placeholder="Price ₹" min="0" oninput="calcManualBill()"/></div>`;
  c.appendChild(div);
  calcManualBill();
}
function calcManualBill(){
  var dishes=document.querySelectorAll('.m-dish');
  var qtys=document.querySelectorAll('.m-qty');
  var prices=document.querySelectorAll('.m-price');
  var sub=0; var previewRows='';
  dishes.forEach(function(_,i){
    var dname=dishes[i].value||'Item '+(i+1);
    var qty=parseInt(qtys[i].value)||1;
    var price=parseFloat(prices[i].value)||0;
    var total=qty*price; sub+=total;
    if(price>0) previewRows+='<div class="bill-row"><span>'+dname+' \u00d7 '+qty+'</span><span>\u20b9 '+total.toLocaleString('en-IN')+'</span></div>';
  });
  var disc=parseFloat(document.getElementById('m-discount').value)||0;
  var discAmt=Math.round(sub*disc/100);
  var couponDiscAmt=0;
  var ac=window._appliedCoupon||null;
  var cpRow=document.getElementById('m-coupon-disc-row');
  var cpMsg=document.getElementById('m-coupon-msg');
  if(ac){
    if(sub>=ac.minorder){
      if(ac.type==='percent'||ac.type==='both') couponDiscAmt+=Math.round(sub*(ac.pct||0)/100);
      if(ac.type==='flat'||ac.type==='both') couponDiscAmt+=Number(ac.flat||0);
      if(ac.maxdisc&&couponDiscAmt>ac.maxdisc) couponDiscAmt=Number(ac.maxdisc);
      if(cpRow){cpRow.style.display='';var cn=document.getElementById('m-coupon-applied-name');if(cn)cn.textContent=ac.code;var cs=document.getElementById('m-coupon-disc-show');if(cs)cs.textContent='\u2014 \u20b9 '+couponDiscAmt.toLocaleString('en-IN');}
      if(cpMsg) cpMsg.innerHTML='<span style="color:#27ae60">\u2705 Coupon "'+ac.code+'" active \u2014 \u20b9'+couponDiscAmt.toLocaleString('en-IN')+' off!</span>';
    } else {
      if(cpRow) cpRow.style.display='none'; couponDiscAmt=0;
      if(cpMsg) cpMsg.innerHTML='<span style="color:#e67e22">\u26a0\ufe0f Min \u20b9'+ac.minorder+' required (current \u20b9'+sub+') \u2014 increase order total to activate coupon</span>';
    }
  } else { if(cpRow) cpRow.style.display='none'; }
  var afterDisc=Math.max(0,sub-discAmt-couponDiscAmt);
  var gstRate=(typeof RS!=='undefined'&&RS.gstRate)||5;
  var cgst=Math.round(afterDisc*(gstRate/2)/100);
  var sgst=cgst;
  var total=afterDisc+cgst+sgst;
  document.getElementById('m-preview-items').innerHTML=previewRows;
  document.getElementById('m-subtotal').textContent='\u20b9 '+sub.toLocaleString('en-IN');
  document.getElementById('m-cgst').textContent='\u20b9 '+cgst.toLocaleString('en-IN');
  document.getElementById('m-sgst').textContent='\u20b9 '+sgst.toLocaleString('en-IN');
  document.getElementById('m-disc-show').textContent=discAmt>0?'\u2014 \u20b9 '+discAmt.toLocaleString('en-IN'):'\u2014';
  document.getElementById('m-total').textContent='\u20b9 '+total.toLocaleString('en-IN');
  document.getElementById('m-bill-meta').textContent='BILL #'+document.getElementById('m-bill-no').value+' \u00b7 '+document.getElementById('m-table').value;
  window._manualBillData={sub:sub,discAmt:discAmt,couponDiscAmt:couponDiscAmt,couponCode:ac?ac.code:'',cgst:cgst,sgst:sgst,total:total,gstRate:gstRate};
}

function getManualBillData(){
  const dishes=document.querySelectorAll('.m-dish');
  const qtys=document.querySelectorAll('.m-qty');
  const prices=document.querySelectorAll('.m-price');
  const order=[];
  dishes.forEach((_,i)=>{ const p=parseFloat(prices[i].value)||0; if(p>0) order.push({name:dishes[i].value||'Item '+(i+1),qty:parseInt(qtys[i].value)||1,price:p*((parseInt(qtys[i].value)||1))}); });
  const d=window._manualBillData||{sub:0,discAmt:0,cgst:0,sgst:0,total:0};
  const billNum=document.getElementById('m-bill-no').value;
  const now=new Date();
  return {order,billNum,table:document.getElementById('m-table').value,cust:document.getElementById('m-cust').value,phone:document.getElementById('m-phone').value,timeStr:now.toLocaleString('en-IN',{day:'2-digit',month:'short',year:'numeric',hour:'2-digit',minute:'2-digit'}),...d};
}
function printManualBill(){
  const d=getManualBillData();
  if(typeof autoSaveCustomerFromBill==='function' && (d.cust||d.phone)){
    const topDish = d.order && d.order.length ? d.order[0].name : '';
    autoSaveCustomerFromBill({ name:d.cust, phone:d.phone, spent:d.total, dish:topDish, tableNum:d.table, waiter:'—', allItems:d.order, billNum:d.billNum, pax:1 });
  }
  const w=window.open('','_blank');
  let rows='';
  d.order.forEach(i=>{ rows+=`<tr><td>${i.name}</td><td style="text-align:right">₹ ${i.price.toLocaleString('en-IN')}</td></tr>`; });
  w.document.write(buildPrintHTML(rows,{tableNum:d.table,td:{pax:'—'},sub:d.sub,cgst:d.cgst,sgst:d.sgst,total:d.total,timeStr:d.timeStr,billNum:d.billNum}));
  w.document.close();
  setTimeout(()=>w.print(),400);
}
function whatsappManualBill(){
  const d=getManualBillData();
  if(typeof autoSaveCustomerFromBill==='function' && (d.cust||d.phone)){
    const topDish = d.order && d.order.length ? d.order[0].name : '';
    autoSaveCustomerFromBill({ name:d.cust, phone:d.phone, spent:d.total, dish:topDish, tableNum:d.table, waiter:'—', allItems:d.order, billNum:d.billNum, pax:1 });
  }
  let items='';
  d.order.forEach(i=>{ items+=`• ${i.name} — ₹${i.price.toLocaleString('en-IN')}\n`; });
  const phone=d.phone.replace(/\D/g,'');
  const msg=`*${_si(11)}️ ${RS.name}*\n${RS.addr}\n${d.timeStr}\nBill #${d.billNum} | ${d.table}\nCustomer: ${d.cust||'Guest'}\n\n${items}TOTAL: ₹${d.total.toLocaleString('en-IN')}\n\nThank you! ${_si(38)}`;
  const url=phone?`https://wa.me/${phone}?text=${encodeURIComponent(msg)}`:`https://wa.me/?text=${encodeURIComponent(msg)}`;
  window.open(url,'_blank');
}
