function populateManualTableSelect(){
  const sel=document.getElementById('m-table');
  if(!sel) return;
  const current=sel.value;
  sel.innerHTML='<option value="">— Select Table —</option>';
  const sorted=Object.entries(tables).sort((a,b)=>parseInt(a[0])-parseInt(b[0]));
  sorted.forEach(([tn,td])=>{
    const opt=document.createElement('option');
    const label=`Table ${String(tn).padStart(2,'0')} · ${td.floor} · ${td.pax} pax · ${td.status}`;
    opt.value=`Table ${String(tn).padStart(2,'0')}`;
    opt.textContent=label;
    if(td.status==='occupied') opt.textContent=_si(39) + ' '+label;
    else if(td.status==='reserved') opt.textContent=_si(39) + ' '+label;
    else opt.textContent=_si(39) + ' '+label;
    sel.appendChild(opt);
  });
  if(current) sel.value=current;
}
