let editingDishId = null; // Firebase doc ID for editing

function _buildMenuCardBody(d, idx, showDelete) {
  let imgEl = document.createElement('div');
  imgEl.style.cssText = 'position:relative;';
  if(d.imageUrl){
    const im = document.createElement('img');
    im.crossOrigin = 'anonymous';
    im.src = d.imageUrl;
    im.style.cssText = 'width:100%;height:110px;object-fit:cover;display:block;border-radius:14px 14px 0 0;';
    im.onerror = function(){ this.style.display='none'; };
    imgEl.appendChild(im);
  } else {
    const em = document.createElement('div');
    em.style.cssText = 'width:100%;height:110px;background:linear-gradient(135deg,var(--dark3),var(--dark4));display:flex;align-items:center;justify-content:center;font-size:36px;border-radius:14px 14px 0 0;';
    const _emojiVal = d.emoji || '🍽️'; if(_emojiVal.trim().startsWith('<')){ em.innerHTML = _emojiVal; } else { em.textContent = _emojiVal; }
    imgEl.appendChild(em);
  }
  const statusPill = document.createElement('span');
  statusPill.style.cssText = 'position:absolute;top:7px;right:8px;padding:2px 8px;border-radius:20px;font-size:9px;font-family:var(--font-ui);font-weight:600;letter-spacing:0.5px;' +
    (d.active ? 'background:rgba(34,197,94,0.9);color:#fff;' : 'background:rgba(239,68,68,0.9);color:#fff;');
  statusPill.textContent = d.active ? 'ACTIVE' : 'INACTIVE';
  imgEl.appendChild(statusPill);

  const body = document.createElement('div');
  body.style.cssText = 'padding:10px 12px 12px;';

  const nameEl = document.createElement('div');
  nameEl.style.cssText = 'font-family:var(--font-royal);font-size:15px;color:var(--cream);margin-bottom:5px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;';
  nameEl.title = d.name;
  nameEl.textContent = d.name;
  body.appendChild(nameEl);

  const priceRow = document.createElement('div');
  priceRow.style.cssText = 'display:flex;align-items:center;gap:6px;flex-wrap:wrap;margin-bottom:4px;';
  priceRow.innerHTML = '<span style="font-family:var(--font-royal);font-size:16px;color:var(--gold-light)">₹'+d.price+'</span>'
    + '<span style="font-size:9px;color:rgba(245,240,232,0.35);background:rgba(201,168,76,0.08);padding:1px 6px;border-radius:8px;font-family:var(--font-ui)">FULL</span>'
    + (d.halfPrice ? '<span style="font-family:var(--font-royal);font-size:13px;color:rgba(201,168,76,0.6)">₹'+d.halfPrice+'</span><span style="font-size:9px;color:rgba(245,240,232,0.3);background:rgba(201,168,76,0.05);padding:1px 6px;border-radius:8px;font-family:var(--font-ui)">HALF</span>' : '');
  body.appendChild(priceRow);

  const metaEl = document.createElement('div');
  metaEl.style.cssText = 'font-family:var(--font-ui);font-size:10px;color:rgba(245,240,232,0.4);margin-bottom:8px;';
  let meta = [(d.cat||''), (d.type||'')].filter(Boolean).join(' · ');
  if(d.dealLabel) meta += ' · <span style="color:#ffa500">'+d.dealLabel+'</span>';
  if(d.rating) meta += ' · <span style="color:var(--gold)">'+_si(1)+' '+parseFloat(d.rating).toFixed(1)+'</span>';
  metaEl.innerHTML = meta;
  body.appendChild(metaEl);

  const btnRow = document.createElement('div');
  btnRow.style.cssText = 'display:flex;gap:6px;';
  btnRow.innerHTML = '<button onclick="editMenuItemUI('+idx+')" style="flex:1;padding:5px 0;background:rgba(201,168,76,0.1);border:1px solid rgba(201,168,76,0.3);color:var(--gold-light);border-radius:8px;font-family:var(--font-ui);font-size:10px;font-weight:600;letter-spacing:0.5px;cursor:pointer;">EDIT</button>'
    + (showDelete ? '<button onclick="deleteMenuItem('+idx+')" style="flex:1;padding:5px 0;background:rgba(231,76,60,0.1);border:1px solid rgba(231,76,60,0.3);color:#e74c3c;border-radius:8px;font-family:var(--font-ui);font-size:10px;font-weight:600;letter-spacing:0.5px;cursor:pointer;">DELETE</button>' : '');
  body.appendChild(btnRow);

  return {imgEl, body};
}

function renderFilteredMenuCards(gridId, filterFn){
  const grid = document.getElementById(gridId);
  if(!grid) return;
  grid.innerHTML = '';
  const filtered = menuItems.filter(filterFn);
  if(!filtered.length){
    grid.innerHTML = '<div style="color:rgba(245,240,232,0.3);font-family:var(--font-ui);font-size:13px;grid-column:1/-1;padding:40px;text-align:center">No dishes in this section. Toggle a section tag to add dishes.</div>';
    return;
  }
  filtered.forEach(function(d){
    const realIdx = menuItems.indexOf(d);
    const card = document.createElement('div');
    card.style.cssText = 'background:var(--glass);border:1px solid var(--glass-border);border-radius:14px;overflow:hidden;transition:box-shadow 0.3s;';
    const parts = _buildMenuCardBody(d, realIdx, false);
    card.appendChild(parts.imgEl);
    card.appendChild(parts.body);
    grid.appendChild(card);
  });
}

function renderMenuCards(filterFn){
  const grid=document.getElementById('menu-cards');
  if(!grid)return;
  grid.innerHTML='';
  const items = filterFn ? menuItems.filter(filterFn) : menuItems;
  if(!items.length){
    grid.innerHTML='<div style="text-align:center;padding:40px;color:rgba(245,240,232,0.3);font-family:var(--font-ui);font-size:13px;grid-column:1/-1">No dishes found</div>';
    return;
  }
  items.forEach(function(d){
    const i = menuItems.indexOf(d);
    const card = document.createElement('div');
    card.style.cssText = 'background:var(--glass);border:1px solid var(--glass-border);border-radius:14px;overflow:hidden;transition:box-shadow 0.3s;';
    const parts = _buildMenuCardBody(d, i, true);
    card.appendChild(parts.imgEl);
    card.appendChild(parts.body);
    grid.appendChild(card);
  });
  if(!filterFn){
    const add=document.createElement('div');
    add.style.cssText='border:2px dashed rgba(201,168,76,0.2);border-radius:14px;display:flex;align-items:center;justify-content:center;cursor:pointer;min-height:260px;transition:all 0.3s';
    add.innerHTML='<div style="text-align:center"><div style="font-size:36px;color:var(--gold-dim)">+</div><div style="font-family:var(--font-ui);font-size:11px;letter-spacing:2px;color:var(--gold-dim);margin-top:8px">ADD DISH</div></div>';
    add.onclick=function(){ editingDishId=null; clearDishForm(); switchMenuTab(document.querySelectorAll('#page-menu .tab')[1],'menu-add'); };
    grid.appendChild(add);
  }
}

function searchMenuDishes(val){
  const q = val.trim().toLowerCase();
  const countEl = document.getElementById('menu-search-count');
  if(!q){
    renderMenuCards();
    if(countEl) countEl.textContent = menuItems.length + ' dishes';
    return;
  }
  const filtered = menuItems.filter(d =>
    (d.name||'').toLowerCase().includes(q) ||
    (d.cat||'').toLowerCase().includes(q) ||
    (d.type||'').toLowerCase().includes(q) ||
    (d.desc||'').toLowerCase().includes(q) ||
    (d.dealLabel||'').toLowerCase().includes(q)
  );
  const grid = document.getElementById('menu-cards');
  if(!grid) return;
  grid.innerHTML = '';
  if(!filtered.length){
    grid.innerHTML = `<div style="text-align:center;padding:40px;color:rgba(245,240,232,0.3);font-family:var(--font-ui);font-size:13px">${_si(41)} No results found for "${val}"</div>`;
    if(countEl) countEl.textContent = '0 results';
    return;
  }
  if(countEl) countEl.textContent = filtered.length + ' results';
  renderMenuCards(d =>
    (d.name||'').toLowerCase().includes(q) ||
    (d.cat||'').toLowerCase().includes(q) ||
    (d.type||'').toLowerCase().includes(q) ||
    (d.desc||'').toLowerCase().includes(q) ||
    (d.dealLabel||'').toLowerCase().includes(q)
  );
}

function clearMenuSearch(){
  const inp = document.getElementById('menu-search-input');
  if(inp) inp.value = '';
  const countEl = document.getElementById('menu-search-count');
  if(countEl) countEl.textContent = menuItems.length + ' dishes';
  renderMenuCards();
}

