async function sendAIQuery(){
  const input=document.getElementById('ai-input');
  const win=document.getElementById('ai-chat-win');
  const q=input.value.trim();
  if(!q)return;
  input.value='';
  win.innerHTML+=`<div style="margin-top:12px;text-align:right"><span style="background:rgba(201,168,76,0.15);border:1px solid rgba(201,168,76,0.3);border-radius:10px;padding:8px 14px;font-family:var(--font-ui);font-size:12px;display:inline-block">${_si(19)} ${q}</span></div>`;
  const thinkId='think-'+Date.now();
  win.innerHTML+=`<div id="${thinkId}" style="margin-top:10px"><span style="background:rgba(41,128,185,0.1);border:1px solid rgba(41,128,185,0.2);border-radius:10px;padding:8px 14px;font-family:var(--font-ui);font-size:12px;display:inline-block;color:#3498db">${_si(61)} Thinking... ${_si(17)}</span></div>`;
  win.scrollTop=win.scrollHeight;
  if(window.geminiAssistantChat){
    const ans = await window.geminiAssistantChat(q);
    const el=document.getElementById(thinkId);
    if(el) el.innerHTML=`<span style="background:rgba(41,128,185,0.15);border:1px solid rgba(41,128,185,0.3);border-radius:10px;padding:8px 14px;font-family:var(--font-ui);font-size:12px;display:inline-block;color:#3498db;white-space:pre-line">${_si(61)} ${ans}</span>`;
  } else {
    const el=document.getElementById(thinkId);
    if(el) el.innerHTML=`<span style="background:rgba(41,128,185,0.15);border:1px solid rgba(41,128,185,0.3);border-radius:10px;padding:8px 14px;font-family:var(--font-ui);font-size:12px;display:inline-block;color:#3498db">${_si(61)} AI is loading, please try again.</span>`;
  }
  win.scrollTop=win.scrollHeight;
}
