const themes=['','neon-theme','glass-theme'];
let themeIdx=0;
const themeNames=['Royal Dark','Neon','Glass'];
function cycleTheme(){
  document.body.classList.remove(...themes.filter(Boolean));
  themeIdx=(themeIdx+1)%themes.length;
  if(themes[themeIdx]) document.body.classList.add(themes[themeIdx]);
  showToast('Theme: '+themeNames[themeIdx],'info');
}

// == SIPLORA NOTIFICATION SOUNDS v3 (Airline Cabin Chime) ==
var _sipAudioCtx = null;
function _getSipAudio() {
  if (!_sipAudioCtx) {
    try { _sipAudioCtx = new (window.AudioContext || window.webkitAudioContext)(); } catch(e) {}
  }
  return _sipAudioCtx;
}

// Realistic airline cabin bell tone — tuning fork + bell body + cabin air resonance
function _airlineChimeTone(ctx, freq, startT, vol, master) {
  // Layer 1: Pure sine — fundamental "tuning fork" tone
  var o1 = ctx.createOscillator(), g1 = ctx.createGain();
  o1.type = 'sine';
  o1.frequency.setValueAtTime(freq, startT);
  g1.gain.setValueAtTime(0.0001, startT);
  g1.gain.linearRampToValueAtTime(vol * 0.75, startT + 0.008);
  g1.gain.setValueAtTime(vol * 0.75, startT + 0.014);
  g1.gain.exponentialRampToValueAtTime(0.0001, startT + 1.65);
  o1.connect(g1); g1.connect(master);
  o1.start(startT); o1.stop(startT + 1.7);

  // Layer 2: Inharmonic partial — real bell physics (2.756x = metallic ring)
  var o2 = ctx.createOscillator(), g2 = ctx.createGain();
  o2.type = 'sine';
  o2.frequency.setValueAtTime(freq * 2.756, startT);
  g2.gain.setValueAtTime(0.0001, startT);
  g2.gain.linearRampToValueAtTime(vol * 0.28, startT + 0.006);
  g2.gain.exponentialRampToValueAtTime(0.0001, startT + 0.50);
  o2.connect(g2); g2.connect(master);
  o2.start(startT); o2.stop(startT + 0.55);

  // Layer 3: Triangle sub — warm hollow body resonance
  var o3 = ctx.createOscillator(), g3 = ctx.createGain();
  o3.type = 'triangle';
  o3.frequency.setValueAtTime(freq * 0.5, startT);
  g3.gain.setValueAtTime(0.0001, startT);
  g3.gain.linearRampToValueAtTime(vol * 0.16, startT + 0.015);
  g3.gain.exponentialRampToValueAtTime(0.0001, startT + 0.75);
  o3.connect(g3); g3.connect(master);
  o3.start(startT); o3.stop(startT + 0.8);

  // Layer 4: High sine — cabin air shimmer / attack sparkle
  var o4 = ctx.createOscillator(), g4 = ctx.createGain();
  o4.type = 'sine';
  o4.frequency.setValueAtTime(freq * 4.0, startT);
  g4.gain.setValueAtTime(0.0001, startT);
  g4.gain.linearRampToValueAtTime(vol * 0.07, startT + 0.005);
  g4.gain.exponentialRampToValueAtTime(0.0001, startT + 0.18);
  o4.connect(g4); g4.connect(master);
  o4.start(startT); o4.stop(startT + 0.22);
}

function _sipPlaySound(type) {
  var ctx = _getSipAudio(); if (!ctx) return;
  if (ctx.state === 'suspended') ctx.resume();
  var t = ctx.currentTime;

  // Soft cabin reverb — delay feedback loop simulates cabin echo
  var delay = ctx.createDelay(0.5);
  delay.delayTime.setValueAtTime(0.09, t);
  var fbGain = ctx.createGain();
  fbGain.gain.setValueAtTime(0.15, t);
  delay.connect(fbGain);
  fbGain.connect(delay);

  var master = ctx.createGain();
  master.gain.setValueAtTime(0.60, t);
  master.connect(delay);
  master.connect(ctx.destination);
  delay.connect(ctx.destination);

  if (type === 'success') {
    // Emirates / Singapore Airlines — iconic 3-note ascending chime
    // D5 -> F#5 -> A5  (D major triad — warm, premium, "everything is perfect")
    _airlineChimeTone(ctx, 587.33, t + 0.00, 0.90, master); // D5
    _airlineChimeTone(ctx, 739.99, t + 0.30, 0.85, master); // F#5
    _airlineChimeTone(ctx, 880.00, t + 0.60, 0.95, master); // A5

  } else if (type === 'warning') {
    // Lufthansa / Air India — double ding, same note, "attention please"
    // Two G5 chimes — firm, cabin-authoritative
    _airlineChimeTone(ctx, 783.99, t + 0.00, 0.88, master); // G5
    _airlineChimeTone(ctx, 783.99, t + 0.40, 0.80, master); // G5

  } else if (type === 'error') {
    // Descending 2-note — "please note" alert style
    // A5 -> D5 — gentle authority, not alarming, still cabin-polite
    _airlineChimeTone(ctx, 880.00, t + 0.00, 0.85, master); // A5
    _airlineChimeTone(ctx, 587.33, t + 0.40, 0.78, master); // D5

  } else {
    // British Airways / Qatar — single clean one-note info ping
    // E5 — neutral, professional, non-intrusive
    _airlineChimeTone(ctx, 659.25, t + 0.00, 0.85, master); // E5
  }
}
