const _NOTIF_CONFIG = {
  success: { color:'#22c55e', colorBg:'rgba(34,197,94,0.15)',  colorGlow:'rgba(34,197,94,0.35)',  label:'SUCCESS', duration:4000 },
  warning: { color:'#fbbf24', colorBg:'rgba(251,191,36,0.15)', colorGlow:'rgba(251,191,36,0.35)', label:'WARNING', duration:5000 },
  error:   { color:'#f87171', colorBg:'rgba(248,113,113,0.15)',colorGlow:'rgba(248,113,113,0.35)',label:'ALERT',   duration:6000 },
  info:    { color:'#f97316', colorBg:'rgba(249,115,22,0.15)', colorGlow:'rgba(249,115,22,0.35)', label:'INFO',    duration:4000 },
};

// Smart icon detection from message keywords
function _getNotifSVG(msg, type) {
  const m = msg.toLowerCase();
  if (m.includes('order') || m.includes('kot')) return _NOTIF_SVG.order;
  if (m.includes('bill') || m.includes('payment') || m.includes('paid') || m.includes('invoice')) return _NOTIF_SVG.bill;
  if (m.includes('table')) return _NOTIF_SVG.table;
  if (m.includes('staff') || m.includes('employee')) return _NOTIF_SVG.staff;
  if (m.includes('sync') || m.includes('connected') || m.includes('live') || m.includes('cloud')) return _NOTIF_SVG.sync;
  if (m.includes('menu') || m.includes('dish') || m.includes('item') || m.includes('food')) return _NOTIF_SVG.menu;
  if (m.includes('delete') || m.includes('removed') || m.includes('clear')) return _NOTIF_SVG.delete;
  if (m.includes('save') || m.includes('saved') || m.includes('added') || m.includes('created')) return _NOTIF_SVG.save;
  if (m.includes('coupon')) return _NOTIF_SVG.coupon;
  if (m.includes('pdf') || m.includes('csv') || m.includes('report') || m.includes('download')) return _NOTIF_SVG.pdf;
  if (m.includes('setting')) return _NOTIF_SVG.settings;
  return _NOTIF_SVG[type] || _NOTIF_SVG.info;
}

// Notification history log (max 50)
window._sipNotifHistory = window._sipNotifHistory || [];

function showToast(msg, type='info') {
  _sipPlaySound(type);
  const cfg = _NOTIF_CONFIG[type] || _NOTIF_CONFIG.info;
  const svgIcon = _getNotifSVG(msg, type);
  const time = new Date().toLocaleTimeString('en-IN',{hour:'2-digit',minute:'2-digit'});
  const id = 'sip-toast-' + Date.now();

  // Save to history
  window._sipNotifHistory.unshift({ id: Date.now(), msg, type, time, svgIcon });
  if (window._sipNotifHistory.length > 50) window._sipNotifHistory.pop();

  // siploraAddNotif NOT called here — it has its own toast, calling it would cause double notifications

  // Ensure container exists
  let container = document.getElementById('sip-premium-toasts');
  if (!container) {
    container = document.createElement('div');
    container.id = 'sip-premium-toasts';
    container.style.cssText = 'position:fixed;top:20px;right:20px;z-index:999999;display:flex;flex-direction:column;gap:10px;pointer-events:none;max-width:360px;';
    document.body.appendChild(container);
  }

  const toast = document.createElement('div');
  toast.id = id;
  // Hardcoded black — NEVER inherits theme colors
  toast.style.cssText = [
    'pointer-events:all',
    'background:#0a0a0f',
    'border-top:1px solid rgba(255,255,255,0.07)',
    'border-right:1px solid rgba(255,255,255,0.07)',
    'border-bottom:1px solid rgba(255,255,255,0.07)',
    'border-left:3px solid ' + cfg.color,
    'border-radius:14px',
    'padding:0',
    'max-width:360px',
    'min-width:310px',
    'box-shadow:0 20px 60px rgba(0,0,0,0.8), 0 4px 20px rgba(0,0,0,0.5), inset 0 1px 0 rgba(255,255,255,0.05)',
    'overflow:hidden',
    'transform:translateX(130%) scale(0.92)',
    'opacity:0',
    'transition:transform 0.42s cubic-bezier(0.34,1.56,0.64,1), opacity 0.3s ease',
  ].join(';');

  toast.innerHTML = `
    <div style="display:flex;align-items:flex-start;gap:13px;padding:15px 15px 11px 15px;background:linear-gradient(135deg,rgba(255,255,255,0.025) 0%,transparent 60%)">
      <div style="width:38px;height:38px;border-radius:11px;background:${cfg.colorBg};border:2px solid ${cfg.color};display:flex;align-items:center;justify-content:center;flex-shrink:0;color:${cfg.color};padding:9px;box-sizing:border-box;box-shadow:0 2px 12px ${cfg.colorGlow}">
        ${svgIcon}
      </div>
      <div style="flex:1;min-width:0;padding-top:2px">
        <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:5px">
          <span style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;font-size:9px;font-weight:800;color:${cfg.color};letter-spacing:2px;text-transform:uppercase;opacity:0.9">${cfg.label}</span>
          <span style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;font-size:9px;color:rgba(255,255,255,0.3);letter-spacing:0.5px">${time}</span>
        </div>
        <div style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;font-size:13px;color:#ffffff;line-height:1.55;word-break:break-word;font-weight:400">${msg}</div>
      </div>
      <div onclick="document.getElementById('${id}')?.remove()" style="color:rgba(255,255,255,0.2);cursor:pointer;font-size:20px;line-height:1;padding:0 2px;flex-shrink:0;margin-top:-1px;font-weight:300" onmouseover="this.style.color='rgba(255,255,255,0.8)'" onmouseout="this.style.color='rgba(255,255,255,0.2)'">×</div>
    </div>
    <div style="height:2px;background:rgba(255,255,255,0.04);overflow:hidden">
      <div id="${id}-bar" style="height:100%;width:100%;background:linear-gradient(90deg,${cfg.color},${cfg.color}99);transform-origin:left;transition:transform ${cfg.duration}ms linear"></div>
    </div>
  `;

  container.prepend(toast);

  // Animate in
  requestAnimationFrame(() => {
    requestAnimationFrame(() => {
      toast.style.transform = 'translateX(0) scale(1)';
      toast.style.opacity = '1';
      // Start progress bar drain
      const bar = document.getElementById(id + '-bar');
      if (bar) { requestAnimationFrame(() => { bar.style.transform = 'scaleX(0)'; }); }
    });
  });

  // Auto dismiss
  const timer = setTimeout(() => _sipDismissToast(toast), cfg.duration);
  toast.addEventListener('mouseenter', () => {
    clearTimeout(timer);
    const bar = document.getElementById(id + '-bar');
    if (bar) bar.style.transitionDuration = '0ms';
  });
  toast.addEventListener('mouseleave', () => {
    _sipDismissToast(toast, 1500);
    const bar = document.getElementById(id + '-bar');
    if (bar) { bar.style.transitionDuration = '1500ms'; bar.style.transform = 'scaleX(0)'; }
  });
}

function _sipDismissToast(toast, delay=0) {
  setTimeout(() => {
    toast.style.transform = 'translateX(120%) scale(0.85)';
    toast.style.opacity = '0';
    toast.style.transition = 'transform 0.3s ease, opacity 0.25s ease';
    setTimeout(() => { toast.style.maxHeight = toast.offsetHeight + 'px'; toast.style.marginBottom = '0'; requestAnimationFrame(() => { toast.style.maxHeight = '0'; toast.style.padding = '0'; toast.style.transition += ',max-height 0.3s ease 0.15s,padding 0.3s ease 0.15s'; setTimeout(() => toast.remove(), 400); }); }, 300);
  }, delay);
}
