  loadDiv.id=loadId;
  loadDiv.style.cssText='display:flex;gap:10px;align-items:flex-start';
  loadDiv.innerHTML=`<div style="font-size:20px;flex-shrink:0">${_si(61)}</div><div style="background:rgba(41,128,185,0.12);border:1px solid rgba(41,128,185,0.2);border-radius:12px 12px 12px 0;padding:12px 16px;font-family:var(--font-ui);font-size:12px;color:rgba(245,240,232,0.5);line-height:1.8;max-width:80%">${_si(17)} Gemini AI soch raha hai...</div>`;
  box.appendChild(loadDiv);
  box.scrollTop=box.scrollHeight;
