function trackOrder(){
  const id=document.getElementById('del-track-input')?.value;
  const result=document.getElementById('del-track-result');
  if(!id||!result){showToast('Enter order ID','warning');return;}
  const found=deliveryOrders.find(o=>o.id.toLowerCase()===id.toLowerCase());
  if(found){
    result.innerHTML=`<div class="glass-card"><div style="font-family:var(--font-royal);font-size:18px;color:var(--cream)">${found.id} — ${found.customer}</div><div style="margin-top:8px;font-size:12px;color:rgba(245,240,232,0.6)">Items: ${found.items}<br>Amount: ₹${found.amount}<br>Rider: ${found.rider}<br><b style="color:var(--gold-light)">Status: ${found.status}</b></div></div>`;
  } else {
    result.innerHTML='<div style="color:rgba(245,240,232,0.4);font-size:12px">Order not found.</div>';
  }
}
