let __fbApp=null, __fbDb=null;
let _fbInited=false;

async function initFirebase(){
  if(_fbInited && __fbDb) return __fbDb;
  try {
    await window._siploraFirebaseLoad();
    const {initializeApp, getApps, getFirestore} = window.__firebaseModules || {};
    if(!getApps) throw new Error('getApps is not defined');
    const {collection, doc, getDocs, onSnapshot, addDoc, updateDoc, setDoc, query, where, orderBy, serverTimestamp} = { collection:window.__col,doc:window.__doc,getDocs:window.__getDocs,onSnapshot:window.__onSnapshot,addDoc:window.__addDoc,updateDoc:window.__updateDoc,setDoc:window.__setDoc,query:window.__query,where:window.__where,orderBy:window.__orderBy,serverTimestamp:window.__serverTimestamp };
    const apps = getApps();
    __fbApp = apps.length ? apps[0] : initializeApp(FB_CONFIG);
    __fbDb = getFirestore(__fbApp);
    _fbInited = true;
    window.__db = __fbDb;
    window.__col = collection;
    window.__doc = doc;
    window.__addDoc = addDoc;
    window.__updateDoc = updateDoc;
    window.__setDoc = setDoc;
    window.__onSnapshot = onSnapshot;
    window.__query = query;
    window.__where = where;
    window.__orderBy = orderBy;
    window.__serverTimestamp = serverTimestamp;
    window.__getDocs = getDocs;
    console.log('[Siplora] Firebase connected [icon]');
    return __fbDb;
  } catch(e) {
    console.warn('[Siplora] Firebase offline:', e.message);
    return null;
  }
}

let _fbTablesUnsub = null;
let _fbTablesSyncInited = false;
async function initFirebaseTablesSync(){
  const db = await initFirebase();
  if(!db) return;
  try {
    const {collection, onSnapshot} = {collection: window.__col, onSnapshot: window.__onSnapshot};
    if(_fbTablesUnsub) _fbTablesUnsub();
    // MULTI-RESTAURANT FIX: _sipCol ab root collection + restaurantId
    // filter use karta hai (asli data structure ke hisaab se) — subcollection
    // path exist hi nahi karta is database me.
    const tablesCol = window._sipCol(db,'tables');
    _fbTablesUnsub = onSnapshot(tablesCol, snap => {
      snap.forEach(d => {
        const data = d.data();
        // MULTI-RESTAURANT FIX: document ID ab "{restaurantId}_{tableNum}"
        // bhi ho sakti hai (naye writes se) ya seedha table number bhi
        // (purane data se). Pehle "tableNumber" field try karo, warna
        // doc ID se number nikalo.
        const tNum = data.tableNumber ? parseInt(data.tableNumber) : parseInt(d.id);
        if(!isNaN(tNum)){
          if(!tables[tNum]) tables[tNum] = {status:'available', pax:4, floor:'Ground', order:[]};
          const locallyCleared = tables[tNum].status === 'available' && (!tables[tNum].order || tables[tNum].order.length === 0);
          const recentlyPaid = data.paidAt && (Date.now() - new Date(data.paidAt).getTime() < 86400000);
          const localPaidAt = tables[tNum]._paidAt && (Date.now() - new Date(tables[tNum]._paidAt).getTime() < 86400000);
          let locallyPaid = false;
          try{
            const paidTables2=JSON.parse(localStorage.getItem(window._sipKey('lum_paid_tables'))||'{}');
            if(paidTables2[tNum]){ const pt2=paidTables2[tNum]; const paidOId3=typeof pt2==='object'?pt2.orderId:null; const fbOId3=data._fbOrderId||''; locallyPaid=(paidOId3&&fbOId3)?paidOId3===fbOId3:true; }
          }catch(e){}
          if((recentlyPaid || locallyPaid || localPaidAt) && data.status === 'occupied'){
            tables[tNum].status = 'available';
            tables[tNum].order = [];
          } else if(data.status) {
            tables[tNum].status = data.status;
          }
          if(data.pax) tables[tNum].pax = data.pax;
          if(data.floor) tables[tNum].floor = data.floor;
          if(data.currentOrder && !locallyCleared) tables[tNum].order = data.currentOrder;
        }
      });
      save('tables', tables);
      window.tables = tables; // FIX: Keep window.tables in sync with Firebase live data
      if(document.getElementById('page-tables')?.classList.contains('active')){
        renderMainTableGrid(activeFloor);
      }
      if(document.getElementById('page-billing')?.classList.contains('active')){
        buildAutoBillGrid();
      }
      if(document.getElementById('page-captain')?.classList.contains('active')){
        _ccRefreshStats();
      }
    });
    if(!_fbTablesSyncInited){ _fbTablesSyncInited=true; showToast(_si(39) + ' Tables — Sync LIVE!','success'); }
  } catch(e){
    console.warn('Tables sync error:', e);
  }
}

let _fbOrdersUnsub = null;
let _fbOrdersSyncInited = false;
async function initFirebaseOrdersSync(){
  const db = await initFirebase();
  if(!db) return;
  try {
    if(_fbOrdersUnsub) _fbOrdersUnsub();
    // MULTI-RESTAURANT FIX: _sipCol ab root collection + restaurantId
    // filter use karta hai — subcollection path exist nahi karta.
    const ordersCol = window._sipCol(db,'orders');
    _fbOrdersUnsub = window.__onSnapshot(
      ordersCol,
      snap => {
        const activeTables = new Set();
        snap.forEach(d => {
          const order = d.data();
          const tNum = parseInt(order.tableNumber || order.table || 0);
          if(!tNum || isNaN(tNum)) return;
          if(order.status === 'paid' || order.status === 'cancelled') return;
          if(order.paidAt && (Date.now() - new Date(order.paidAt).getTime() < 86400000)) return;
          try{
            const paidTables=JSON.parse(localStorage.getItem(window._sipKey('lum_paid_tables'))||'{}');
            if(paidTables[tNum]){
              const ptEntry2=paidTables[tNum]; const paidOId2=typeof ptEntry2==='object'?ptEntry2.orderId:null; const curOId2=d.id||'';
              if(paidOId2 && curOId2 && paidOId2===curOId2) return; // Same paid order
              delete paidTables[tNum]; localStorage.setItem(window._sipKey('lum_paid_tables'),JSON.stringify(paidTables)); // New order — clear
            }
          }catch(e){}
          activeTables.add(tNum); // Yeh table occupied hai
        });

        snap.forEach(d => {
          const order = d.data();
          const tNum = parseInt(order.tableNumber || order.table || 0);
          if(order.status === 'paid' || order.status === 'cancelled') return;
          if(order.paidAt && (Date.now() - new Date(order.paidAt).getTime() < 86400000)) return;
          if(!tNum || isNaN(tNum)) return;
          try{
            const paidTables=JSON.parse(localStorage.getItem(window._sipKey('lum_paid_tables'))||'{}');
            if(paidTables[tNum] && (Date.now()-new Date(paidTables[tNum]).getTime()<86400000)) return;
          }catch(e){}
          if(tNum){
            if(!tables[tNum]) tables[tNum] = {status:'available', pax:4, floor:'Ground', order:[]};
            tables[tNum].status = activeTables.has(tNum) ? 'occupied' : (tables[tNum].status === 'reserved' ? 'reserved' : 'available');
            tables[tNum]._fbOrderId = d.id;

            if(order.customerName) tables[tNum].customerName = order.customerName;
            if(order.customerPhone) tables[tNum].customerPhone = order.customerPhone;
            if(order.custName) tables[tNum].customerName = tables[tNum].customerName || order.custName;
            if(order.phone) tables[tNum].customerPhone = tables[tNum].customerPhone || order.phone;
            if(order.name) tables[tNum].customerName = tables[tNum].customerName || order.name;

            const items = order.items || order.orderItems || order.cart || [];
            if(items.length > 0){
              tables[tNum].order = items.map(it => {
                let unitPrice = parseFloat(it.priceNum) || parseFloat(it.price) || parseFloat(it.itemPrice) || parseFloat(it.unitPrice) || 0;
                if(!unitPrice && typeof it.price === 'string'){
                  unitPrice = parseFloat(it.price.replace(/[^\d.]/g,'')) || 0;
                }
                if(!unitPrice){
                  const menuMatch = menuItems.find(m => m.name.toLowerCase() === String(it.name||it.itemName||'').toLowerCase());
                  if(menuMatch) unitPrice = parseFloat(menuMatch.price) || 0;
                }
                return {
                  name: it.name || it.itemName || it.dishName || 'Item',
                  qty: parseInt(it.qty) || parseInt(it.quantity) || parseInt(it.count) || 1,
                  price: unitPrice
                };
              });
            }
          }
        });
        save('tables', tables);
        _liveOrders = [];
        snap.forEach(d => _liveOrders.push({_id:d.id,...d.data()}));
        if(document.getElementById('page-tables')?.classList.contains('active')){
          renderFloorTabs(); renderMainTableGrid(activeFloor);
        }
        if(document.getElementById('page-billing')?.classList.contains('active')){
          buildAutoBillGrid();
        }
        if(document.getElementById('page-orders')?.classList.contains('active')) renderOrdersPage();
        if(document.getElementById('page-kds')?.classList.contains('active')) renderKDSPage();
        window.tables = tables; // FIX: Keep window.tables in sync after orders update
        if(document.getElementById('page-captain')?.classList.contains('active')){
          _ccRefreshStats();
        }
        renderDashboardOrders(snap);
      }
    );
    if(!_fbOrdersSyncInited){ _fbOrdersSyncInited=true; showToast(_si(24) + ' Orders — Sync LIVE!','success'); }
  } catch(e){
    console.warn('Orders sync error:', e);
  }
}

function renderDashboardOrders(snap){
  const box = document.getElementById('live-orders-box');
  if(!box) return;
  box.innerHTML = '';
  const orders = [];
  snap.forEach(d => orders.push({id:d.id, ...d.data()}));
  const active = orders.filter(o => o.status !== 'paid' && o.status !== 'cancelled').slice(0,6);
  if(active.length === 0){
    box.innerHTML = '<div style="color:rgba(245,240,232,0.3);font-size:12px;text-align:center;padding:16px">No active orders right now</div>';
    return;
  }
  const pendingC=active.filter(o=>o.status==='pending'||!o.status).length;
  const cookingC=active.filter(o=>o.status==='cooking'||o.status==='preparing').length;
  const readyC=active.filter(o=>o.status==='ready').length;
  const summary=document.createElement('div');
  summary.style.cssText='display:flex;gap:10px;margin-bottom:10px;padding-bottom:10px;border-bottom:1px solid rgba(201,168,76,0.1);';
  summary.innerHTML=`
    <div style="flex:1;text-align:center;padding:8px;background:rgba(192,57,43,.08);border-radius:8px;border:1px solid rgba(192,57,43,.2);">
      <div style="font-family:var(--font-royal);font-size:20px;color:#e74c3c;">${pendingC}</div>
      <div style="font-family:var(--font-ui);font-size:9px;color:rgba(245,240,232,.4);letter-spacing:1.5px;">PENDING</div>
    </div>
    <div style="flex:1;text-align:center;padding:8px;background:rgba(41,128,185,.08);border-radius:8px;border:1px solid rgba(41,128,185,.2);">
      <div style="font-family:var(--font-royal);font-size:20px;color:#3498db;">${cookingC}</div>
      <div style="font-family:var(--font-ui);font-size:9px;color:rgba(245,240,232,.4);letter-spacing:1.5px;">COOKING ${_si(45)}</div>
    </div>
    <div style="flex:1;text-align:center;padding:8px;background:rgba(39,174,96,.08);border-radius:8px;border:1px solid rgba(39,174,96,.2);">
      <div style="font-family:var(--font-royal);font-size:20px;color:#2ecc71;">${readyC}</div>
      <div style="font-family:var(--font-ui);font-size:9px;color:rgba(245,240,232,.4);letter-spacing:1.5px;">READY ${_si(28)}</div>
    </div>`;
  box.appendChild(summary);
  active.forEach(o => {
    const items = (o.items||[]).map(i=>i.name+' × '+(i.qty||1)).join(' · ');
    const st=o.status||'pending';
    const statusColor = st==='ready'?'#2ecc71':st==='cooking'||st==='preparing'?'#3498db':'#e74c3c';
    const statusLabel = st==='ready'?_si(28) + ' Ready':st==='cooking'||st==='preparing'?_si(45) + ' Cooking':_si(17) + ' Pending';
    const badgeClass = st==='ready'?'badge-green':st==='cooking'||st==='preparing'?'badge-blue':'badge-red';
    const custLine=o.customerName?`<div style="font-family:var(--font-ui);font-size:10px;color:rgba(245,240,232,.45);margin-top:3px;">${_si(19)} ${o.customerName}${o.customerPhone?' · _si(23) '+o.customerPhone:''}</div>`:'';
    const div = document.createElement('div');
    div.className = 'order-card';
    div.style.setProperty('--accent', statusColor);
    div.innerHTML = `
      <div style="display:flex;justify-content:space-between;align-items:center">
        <span style="font-family:var(--font-royal);font-size:16px">Table ${o.tableNumber||o.table||'?'} — #${o.orderNumber||(o.id||'').slice(-4)}</span>
        <span class="badge ${badgeClass}">${statusLabel}</span>
      </div>
      ${custLine}
      <div style="font-family:var(--font-ui);font-size:11px;color:rgba(245,240,232,0.45);margin-top:5px">${items||'—'}</div>`;
    div.onclick = () => { showPage('billing', document.querySelector('.nav-item[onclick*=billing]')); setTimeout(()=>{ if(o.tableNumber) showAutoBill(parseInt(o.tableNumber)); },300); };
    box.appendChild(div);
  });
}

(async function autoInitFB(){
  // ── MULTI-RESTAURANT: restaurantId set hone ka wait karo ──
  await new Promise(resolve => {
    if (window._sip_restaurantId) return resolve();
    const check = setInterval(() => {
      if (window._sip_restaurantId) { clearInterval(check); resolve(); }
    }, 200);
    // Agar 30 seconds mein nahi mila (login nahi hua) toh bhi continue karo
    setTimeout(() => { clearInterval(check); resolve(); }, 30000);
  });

  await window._siploraFirebaseLoad(); // Load firebase ONCE first
  await initFirebase();
  await initFirebaseTablesSync();
  await initFirebaseOrdersSync();
  // ── Menu sync: app start pe hi load karo, Menu page click ka wait mat karo ──
  if(!window._fbMenuInited){
    initFirebaseMenuSync();
  }
})();


function emailBill(){
  const d = window._autoBillData;
  if(!d){ showToast('Please generate a bill first','warning'); return; }
  let items = '';
  d.td.order.forEach(i=>{
    const unitPrice=parseFloat(i.price)||0;
    const qty=parseInt(i.qty)||1;
    items += i.name+' x'+qty+' = Rs.'+(unitPrice*qty)+'\n';
  });
  const custLine = d.custName ? 'Customer: '+d.custName+(d.custPhone?' | Ph: '+d.custPhone:'')+'\n' : '';
  const subject = encodeURIComponent(RS.name+' — Bill #'+d.billNum);
  const body = encodeURIComponent(
    RS.name+'\n'+RS.addr+'\nPhone: '+RS.phone+'\nGST: '+RS.gst+'\n\n'+
    'Bill #'+d.billNum+' | Table '+d.tableNum+' | '+d.timeStr+'\n'+custLine+'\n'+
    items+'\nSubtotal: Rs.'+d.sub+'\nCGST: Rs.'+d.cgst+'\nSGST: Rs.'+d.sgst+'\nTOTAL: Rs.'+d.total+'\n\nThank you!'
  );
  window.open('mailto:'+(d.custPhone?'':''+'?subject='+subject+'&body='+body),'_blank');
  showToast('Opening email app...','success');
  autoReleaseTable(d.tableNum);
  closeModal('auto-bill-modal');
}

async function markTablePaidAndUpdate(){
  const d=window._autoBillData;
  if(!d) return;

  if(d.td && d.td.order && d.td.order.length){
    deductStockForOrder(d.td.order);
  }

  if(tables[d.tableNum]){
    tables[d.tableNum].status='available';
    tables[d.tableNum].order=[];
    tables[d.tableNum].customerName='';
    tables[d.tableNum].customerPhone='';
    tables[d.tableNum]._fbOrderId=null;
    tables[d.tableNum]._paidAt=new Date().toISOString(); // reload protection
    save('tables',tables);
  }
  try{
    const paidTables=JSON.parse(localStorage.getItem(window._sipKey('lum_paid_tables'))||'{}');
    paidTables[d.tableNum]=new Date().toISOString();
    localStorage.setItem(window._sipKey('lum_paid_tables'),JSON.stringify(paidTables));
  }catch(e){}

  const fbOrderId = d._fbOrderId || (tables[d.tableNum]&&tables[d.tableNum]._fbOrderId);
  if(fbOrderId && window.__fbDb && window.__fbUpdateDoc && window.__fbDoc){
    try{
      await window.__fbUpdateDoc(window.__fbDoc(window.__fbDb,'orders',fbOrderId),{
        status:'paid',
        paidAt:new Date().toISOString(),
        billNum:d.billNum,
        totalBilled:d.total
      });
    }catch(e){ console.warn('Order paid mark error:',e); }
  }
  await markTablePaidFB(d.tableNum);

  // ── Captain Bill Log (owner dashboard ke liye) ──
  (function() {
    var tblNum = String(d.tableNum);
    var capForBill = null;
    if (window._ccCurrentRole === 'captain' && window._ccLoggedInCaptainId) {
      var allC = typeof _ccGetCaptains === 'function' ? _ccGetCaptains() : [];
      capForBill = allC.find(function(c){ return c.id === window._ccLoggedInCaptainId; }) || null;
    }
    if (!capForBill && typeof _ccFindCaptainByTable === 'function') capForBill = _ccFindCaptainByTable(tblNum);
    if (capForBill && typeof _ccSaveCaptainBill === 'function') {
      _ccSaveCaptainBill(capForBill.id, {
        tableNum: tblNum,
        at: new Date().toISOString(),
        amount: d.total || 0,
        captainId: capForBill.id,
        captainName: capForBill.name
      });
    }
  })();

  buildAutoBillGrid();
  if(document.getElementById('page-tables')?.classList.contains('active')){
    renderFloorTabs(); renderMainTableGrid(activeFloor);
  }
  closeModal('auto-bill-modal');
  showToast(_si(28) + ' Bill complete! Table '+d.tableNum+' is now free!','success');
  if(document.getElementById('page-qr-tables')?.classList.contains('active')) buildAllQRCodes();
}

function _getMenuUrl(tableNum){
  const rid = window._sip_restaurantId || '';
  const ridParam = rid ? ('&rid='+encodeURIComponent(rid)) : '';
  const saved=localStorage.getItem(window._sipKey('lum_menu_url'));
  if(saved && saved.trim()){
    const base=saved.trim().replace(/\?.*$/,'').replace(/\/$/, '');
    return base+'?table='+tableNum+ridParam;
  }
  return 'https://anandagadhe376-glitch.github.io/siplora-menu/?table='+tableNum+ridParam;
}

