function saveWaApi(){
  const key=document.getElementById('wa-api-key').value.trim();
  const phoneId=document.getElementById('wa-phone-id').value.trim();
  const bizId=document.getElementById('wa-biz-id').value.trim();
  const provider=document.getElementById('wa-provider').value;
  const customUrl=document.getElementById('wa-custom-url').value.trim();
  if(!key){ showToast('API Key is required!','error'); return; }
  if(provider==='meta' && !phoneId){ showToast('Please enter Phone Number ID!','error'); return; }
  WA_CONFIG = {
    key, phoneId, bizId, provider, customUrl,
    bill: document.getElementById('wa-toggle-bill').classList.contains('on'),
    bday: document.getElementById('wa-toggle-bday').classList.contains('on'),
    order: document.getElementById('wa-toggle-order').classList.contains('on'),
    promo: document.getElementById('wa-toggle-promo').classList.contains('on'),
    connected: true
  };
  localStorage.setItem(window._sipKey('lum_wa_config'), JSON.stringify(WA_CONFIG));
  updateWaStatusBadge(true);
  showToast(_si(28) + ' WhatsApp API saved & connected!','success');
}

