async function sendWhatsAppMessage(toPhone, message){
  if(!WA_CONFIG.key || !WA_CONFIG.connected){
    showToast('WhatsApp API not connected! Please go to Settings.','warning');
    return false;
  }
  try {
    let url, headers={'Content-Type':'application/json'}, body;
    if(WA_CONFIG.provider==='meta'){
      url=`https://graph.facebook.com/v18.0/${WA_CONFIG.phoneId}/messages`;
      headers['Authorization']='Bearer '+WA_CONFIG.key;
      body={messaging_product:'whatsapp',to:toPhone.replace(/\D/g,''),type:'text',text:{body:message}};
    } else if(WA_CONFIG.customUrl){
      url=WA_CONFIG.customUrl;
      headers['Authorization']='Bearer '+WA_CONFIG.key;
      body={to:toPhone,message};
    } else {
      showToast('Please enter custom URL in Settings!','error'); return false;
    }
    const res=await fetch(url,{method:'POST',headers,body:JSON.stringify(body)});
    return res.ok;
  } catch(e){ console.error('WA send error:',e); return false; }
}

