(async function initFirebaseExtras(){
  try{
    await window._siploraFirebaseLoad();
    const db=window.__fbDb;
    const collection=window.__col, onSnapshot=window.__onSnapshot, doc=window.__doc;
    const updateDoc=window.__updateDoc, addDoc=window.__addDoc, getDocs=window.__getDocs;
    const serverTimestamp=window.__serverTimestamp, setDoc=window.__setDoc;
    window.__fbDb=db;
    window.__fbCol=collection;
    window.__fbOnSnapshot=onSnapshot;
    window.__fbDoc=doc;
    window.__fbUpdateDoc=updateDoc;
    window.__fbAddDoc=addDoc;
    window.__fbGetDocs=getDocs;
    window.__fbServerTs=serverTimestamp;
    window.__fbSetDoc=setDoc;
    window.__db=db; window.__col=collection; window.__addDoc=addDoc;
    window.__fbReady=true;
    console.log('[Siplora] Firebase Extras ready [icon]');
    window.dispatchEvent(new Event('firebaseReady'));

    window.__onSnapshot(window._sipCol(db, 'customers'), snap=>{
      customers = snap.docs.map(d=>({ _id:d.id, ...d.data() }));
      const getTier=s=>s>=15000?'Platinum':s>=7000?'Gold':s>=3000?'Silver':'Bronze';
      customers.forEach(c=>{ c.tier=c.tier||getTier(c.spent||0); });
      customers.sort((a,b)=>(b.spent||0)-(a.spent||0));
      renderCustomersTable();
      renderLoyaltyTable();
      renderBirthdayAlerts();
      console.log('[Siplora] Customers loaded from Firebase:',customers.length);
    });

    window.__onSnapshot(window._sipCol(db, 'suppliers'), snap=>{
      suppliers = snap.docs.map(d=>({ _id:d.id, ...d.data() }));
      renderSupplierCards();
      renderSupStockTable();
      const supCount=document.getElementById('sup-count');
      if(supCount) supCount.textContent=suppliers.length;
      console.log('[Siplora] Suppliers loaded from Firebase:',suppliers.length);
    });

  }catch(e){
    console.warn('[Siplora] Firebase Extras failed:',e.message);
    window.__fbReady=false;
  }
})();

