function setText(id,val){ const e=document.getElementById(id); if(e) e.textContent=val; }

let msMenuItems = load('ms_menu_items') || [];
let msCategories = load('ms_categories') || ['Starters','Main Course','Biryani','Breads','Drinks','Desserts','Snacks'];
let msEditId = null;

function msInit(){
  msPopulateCategoryDropdowns();
  msRenderItems();
  msUpdateStats();
}

function msPopulateCategoryDropdowns(){
  const sel = document.getElementById('ms-category');
  const filterSel = document.getElementById('ms-filter-cat');
  if(!sel||!filterSel) return;
  sel.innerHTML = '<option value="">-- Select Category --</option>';
  filterSel.innerHTML = '<option value="">All Categories</option>';
  msCategories.forEach(c=>{
    sel.innerHTML += `<option value="${c}">${c}</option>`;
    filterSel.innerHTML += `<option value="${c}">${c}</option>`;
  });
}

function msUpdateStats(){
  const total = msMenuItems.length;
  const hot = msMenuItems.filter(i=>i.hasDeal).length;
  const active = msMenuItems.filter(i=>i.isActive).length;
  const cats = new Set(msMenuItems.map(i=>i.category).filter(Boolean)).size;
  setText('ms-total-items', total);
  setText('ms-hot-deals', hot);
  setText('ms-active-items', active);
  setText('ms-cat-count', msCategories.length);
}

function msRenderItems(){
  const grid = document.getElementById('ms-items-grid');
  if(!grid) return;
  const catFilter = document.getElementById('ms-filter-cat')?.value || '';
  const dealFilter = document.getElementById('ms-filter-deal')?.value || '';
  let items = [...msMenuItems];
  if(catFilter) items = items.filter(i=>i.category===catFilter);
  if(dealFilter==='deal') items = items.filter(i=>i.hasDeal);
  if(dealFilter==='active') items = items.filter(i=>i.isActive);

  if(items.length===0){
    grid.innerHTML = `<div style="grid-column:1/-1;text-align:center;padding:48px;color:rgba(245,240,232,0.3)">
      <div style="font-size:48px;margin-bottom:12px">${_si(11)}</div>
      <div style="font-family:var(--font-royal);font-size:20px;color:rgba(245,240,232,0.4)">No items found</div>
      <div style="font-family:var(--font-ui);font-size:11px;color:rgba(245,240,232,0.25);margin-top:4px">Use the "+ Add Item" button above to add a new item</div>
    </div>`;
    return;
  }

  grid.innerHTML = items.map(item=>{
    const discPrice = item.hasDeal && item.discount ? Math.round(item.fullRate*(1-item.discount/100)) : null;
    const stars = ''+_si(1)+''.repeat(Math.floor(item.rating||0))+''+_si(1)+''.repeat(5-Math.floor(item.rating||0));
    const days = (item.days||[]).join(', ') || 'All Days';
    const timeStr = item.startTime && item.endTime ? `${item.startTime} – ${item.endTime}` : 'All Hours';
    return `<div class="glass-card" style="padding:0;overflow:hidden;position:relative;transition:all 0.3s">
      ${item.imgUrl?`<div style="position:relative;height:160px;overflow:hidden">
        <img src="${item.imgUrl}" style="width:100%;height:100%;object-fit:cover" onerror="this.parentElement.style.display='none'" alt="${item.name}"/>
        ${item.hasDeal?`<div style="position:absolute;top:10px;left:10px;background:linear-gradient(135deg,#e74c3c,#c0392b);color:white;font-family:var(--font-ui);font-size:10px;font-weight:500;padding:3px 10px;border-radius:20px;letter-spacing:1px">${_si(45)} ${item.dealTitle||'HOT DEAL'} ${item.discount?item.discount+'% OFF':''}</div>`:''}
        <div style="position:absolute;top:10px;right:10px;background:${item.isActive?'rgba(39,174,96,0.85)':'rgba(192,57,43,0.85)'};color:white;font-family:var(--font-ui);font-size:9px;padding:3px 8px;border-radius:12px;letter-spacing:1px">${item.isActive?_si(28) + ' ACTIVE':_si(0) + ' OFF'}</div>
      </div>`:`<div style="height:8px;background:${item.isActive?'linear-gradient(90deg,var(--gold),var(--gold-dim))':'rgba(255,255,255,0.05)'}"></div>`}
      <div style="padding:16px">
        <div style="display:flex;align-items:flex-start;justify-content:space-between;margin-bottom:6px;gap:8px">
          <div>
            <div style="font-family:var(--font-royal);font-size:18px;color:var(--cream)">${item.name}</div>
            ${item.category?`<span style="font-family:var(--font-ui);font-size:9px;letter-spacing:1.5px;color:var(--gold-dim);text-transform:uppercase">${item.category}</span>`:''}
          </div>
          ${item.rating?`<div style="font-family:var(--font-ui);font-size:11px;color:#f1c40f;white-space:nowrap">${parseFloat(item.rating).toFixed(1)} _si(1)</div>`:''}
        </div>
        ${item.description?`<div style="font-family:var(--font-ui);font-size:11px;color:rgba(245,240,232,0.5);margin-bottom:10px;line-height:1.5;display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;overflow:hidden">${item.description}</div>`:''}
        <!-- Price row -->
        <div style="display:flex;align-items:center;gap:10px;margin-bottom:10px;flex-wrap:wrap">
          ${item.halfRate?`<div style="background:rgba(41,128,185,0.1);border:1px solid rgba(41,128,185,0.25);border-radius:8px;padding:4px 10px;text-align:center">
            <div style="font-family:var(--font-ui);font-size:8px;color:#3498db;letter-spacing:1px">HALF</div>
            <div style="font-family:var(--font-royal);font-size:16px;color:#3498db">₹${item.halfRate}</div>
          </div>`:''}
          <div style="background:rgba(201,168,76,0.1);border:1px solid rgba(201,168,76,0.25);border-radius:8px;padding:4px 10px;text-align:center">
            <div style="font-family:var(--font-ui);font-size:8px;color:var(--gold-dim);letter-spacing:1px">FULL</div>
            <div style="font-family:var(--font-royal);font-size:18px;color:var(--gold-light)">₹${item.fullRate||'—'}</div>
          </div>
          ${discPrice?`<div style="background:rgba(231,76,60,0.1);border:1px solid rgba(231,76,60,0.3);border-radius:8px;padding:4px 10px;text-align:center">
            <div style="font-family:var(--font-ui);font-size:8px;color:#e74c3c;letter-spacing:1px">DEAL</div>
            <div style="font-family:var(--font-royal);font-size:18px;color:#e74c3c">₹${discPrice}</div>
          </div>`:''}
        </div>
        <!-- Hours & days -->
        <div style="display:flex;gap:8px;margin-bottom:12px;flex-wrap:wrap">
          <span style="font-family:var(--font-ui);font-size:9px;color:rgba(245,240,232,0.4);background:var(--glass);border:1px solid var(--glass-border);border-radius:6px;padding:2px 8px">${_si(50)} ${timeStr}</span>
          <span style="font-family:var(--font-ui);font-size:9px;color:rgba(245,240,232,0.4);background:var(--glass);border:1px solid var(--glass-border);border-radius:6px;padding:2px 8px">${_si(25)} ${days}</span>
          ${item.itemUrl?`<a href="${item.itemUrl}" target="_blank" style="font-family:var(--font-ui);font-size:9px;color:#3498db;background:rgba(41,128,185,0.1);border:1px solid rgba(41,128,185,0.25);border-radius:6px;padding:2px 8px;text-decoration:none">${_si(79)} Link</a>`:''}
        </div>
        <!-- Actions -->
        <div style="display:flex;gap:6px;flex-wrap:wrap">
          <button class="btn btn-ghost btn-sm" onclick="msOpenEdit('${item.id}')">${_si(42)} Edit</button>
          <button class="btn btn-sm" style="background:${item.isActive?'rgba(192,57,43,0.15)':'rgba(39,174,96,0.15)'};border-color:${item.isActive?'rgba(192,57,43,0.4)':'rgba(39,174,96,0.4)'};color:${item.isActive?'#e74c3c':'#2ecc71'}" onclick="msToggleActive('${item.id}')">${item.isActive?_si(0) + ' Disable':_si(28) + ' Enable'}</button>
          <button class="btn btn-danger btn-sm" onclick="msDeleteItem('${item.id}')">${_si(62)}</button>
        </div>
      </div>
    </div>`;
  }).join('');
}

