function msOpenEdit(id){
  const item = msMenuItems.find(i=>i.id===id);
  if(!item) return;
  msEditId = id;
  msPopulateCategoryDropdowns();
  document.getElementById('ms-modal-title').textContent = _si(42) + ' Item Edit Karo';
  document.getElementById('ms-edit-id').value = id;
  document.getElementById('ms-img-url').value = item.imgUrl||'';
  document.getElementById('ms-item-url').value = item.itemUrl||'';
  document.getElementById('ms-category').value = item.category||'';
  document.getElementById('ms-item-name').value = item.name||'';
  document.getElementById('ms-rating').value = item.rating||'';
  document.getElementById('ms-description').value = item.description||'';
  document.getElementById('ms-half-rate').value = item.halfRate||'';
  document.getElementById('ms-full-rate').value = item.fullRate||'';
  if(item.hasDeal){
    document.getElementById('ms-deal-toggle').classList.add('on');
    document.getElementById('ms-deal-fields').style.display = 'block';
  } else {
    document.getElementById('ms-deal-toggle').classList.remove('on');
    document.getElementById('ms-deal-fields').style.display = 'none';
  }
  document.getElementById('ms-deal-title').value = item.dealTitle||'';
  document.getElementById('ms-discount').value = item.discount||'';
  document.getElementById('ms-start-time').value = item.startTime||'';
  document.getElementById('ms-end-time').value = item.endTime||'';
  if(item.isActive) document.getElementById('ms-active-toggle').classList.add('on');
  else document.getElementById('ms-active-toggle').classList.remove('on');
  if(item.imgUrl){
    document.getElementById('ms-img-preview').style.display = 'block';
    document.getElementById('ms-img-tag').src = item.imgUrl;
  } else {
    document.getElementById('ms-img-preview').style.display = 'none';
  }
  const days = item.days||[];
  document.querySelectorAll('#ms-days-selector input[type=checkbox]').forEach(c=>{ c.checked = days.includes(c.value); });
  document.getElementById('ms-item-modal').classList.add('open');
}

function msSaveItem(){
  const name = document.getElementById('ms-item-name').value.trim();
  if(!name){ showToast('Please enter item name!','warning'); return; }
  const fullRate = parseFloat(document.getElementById('ms-full-rate').value)||0;
  if(!fullRate){ showToast('Full rate is required!','warning'); return; }
  const hasDeal = document.getElementById('ms-deal-toggle').classList.contains('on');
  const days = [...document.querySelectorAll('#ms-days-selector input[type=checkbox]:checked')].map(c=>c.value);
  const item = {
    id: msEditId || 'MS-'+Date.now().toString(36).toUpperCase(),
    name,
    imgUrl: document.getElementById('ms-img-url').value.trim(),
    itemUrl: document.getElementById('ms-item-url').value.trim(),
    category: document.getElementById('ms-category').value,
    rating: parseFloat(document.getElementById('ms-rating').value)||0,
    description: document.getElementById('ms-description').value.trim(),
    halfRate: parseFloat(document.getElementById('ms-half-rate').value)||0,
    fullRate,
    hasDeal,
    dealTitle: hasDeal ? document.getElementById('ms-deal-title').value.trim() : '',
    discount: hasDeal ? parseFloat(document.getElementById('ms-discount').value)||0 : 0,
    startTime: document.getElementById('ms-start-time').value,
    endTime: document.getElementById('ms-end-time').value,
    days,
    isActive: document.getElementById('ms-active-toggle').classList.contains('on'),
    updatedAt: Date.now()
  };
  if(msEditId){
    const idx = msMenuItems.findIndex(i=>i.id===msEditId);
    if(idx>-1) msMenuItems[idx] = item;
  } else {
    item.createdAt = Date.now();
    msMenuItems.unshift(item);
  }
  save('ms_menu_items', msMenuItems);
  closeModal('ms-item-modal');
  msRenderItems();
  msUpdateStats();
  showToast(msEditId?_si(28) + ' Item updated!':_si(28) + ' Naya item added!','success');
  msEditId = null;
}

function msPreviewImg(){
  const url = document.getElementById('ms-img-url').value.trim();
  const prev = document.getElementById('ms-img-preview');
  const img = document.getElementById('ms-img-tag');
  if(url){ prev.style.display='block'; img.src=url; } else { prev.style.display='none'; }
}

function msToggleActive(id){
  const item = msMenuItems.find(i=>i.id===id);
  if(!item) return;
  item.isActive = !item.isActive;
  save('ms_menu_items', msMenuItems);
  msRenderItems();
  msUpdateStats();
  showToast(item.name+' '+(item.isActive?'enabled '+_si(28)+'':'disabled '+_si(0)+''),'success');
}

function msDeleteItem(id){
  const item = msMenuItems.find(i=>i.id===id);
  if(!item) return;
  if(!confirm('"'+item.name+'" delete karna chahte ho?')) return;
  msMenuItems = msMenuItems.filter(i=>i.id!==id);
  save('ms_menu_items', msMenuItems);
  msRenderItems();
  msUpdateStats();
  showToast(_si(62) + ' Item deleted','info');
}

function openMsCatModal(){
  msRenderCatList();
  document.getElementById('ms-cat-modal').classList.add('open');
}

function msRenderCatList(){
  const list = document.getElementById('ms-cat-list');
  if(!list) return;
  list.innerHTML = msCategories.map((c,i)=>`
    <div style="display:flex;align-items:center;gap:8px;padding:8px 12px;background:var(--glass);border:1px solid var(--glass-border);border-radius:8px">
      <span style="font-family:var(--font-ui);font-size:12px;color:var(--cream);flex:1">${_si(43)} ${c}</span>
      <button class="btn btn-danger btn-sm" onclick="msDeleteCategory(${i})" style="padding:4px 8px">${_si(62)}</button>
    </div>`).join('');
}

function msAddCategory(){
  const input = document.getElementById('ms-new-cat-input');
  const val = input.value.trim();
  if(!val){ showToast('Please enter a category name!','warning'); return; }
  if(msCategories.includes(val)){ showToast('Ye category already exists!','warning'); return; }
  msCategories.push(val);
  save('ms_categories', msCategories);
  input.value = '';
  msRenderCatList();
  msPopulateCategoryDropdowns();
  msUpdateStats();
  showToast(_si(28) + ' Category "'+val+'" added!','success');
}

function msDeleteCategory(idx){
  const name = msCategories[idx];
  if(!confirm('"'+name+'" category delete karna chahte ho?')) return;
  msCategories.splice(idx,1);
  save('ms_categories', msCategories);
  msRenderCatList();
  msPopulateCategoryDropdowns();
  msUpdateStats();
  showToast('"'+name+'" deleted','info');
}

