function esDownloadPayslip(){
  const empId = document.getElementById('es-ps-emp')?.value;
  const emp = esEmployees.find(e=>e.id===empId); if(!emp) return;
  const month = Number(document.getElementById('es-ps-month')?.value);
  const year = Number(document.getElementById('es-ps-year')?.value);
  const calc = esCalcSalary(emp, year, month);
  const monthName = new Date(year,month).toLocaleString('default',{month:'long',year:'numeric'});
  const txt = `SALARY SLIP — ${monthName}\n${'='.repeat(40)}\nName: ${emp.name}\nRole: ${emp.category}\nID: ${emp.id}\n${'─'.repeat(40)}\nBase Salary:   ${esFormatINR(emp.salary)}\nWorking Days:  ${calc.workDays}\nDays Present:  ${calc.daysPresent}\nPer Day:       ${esFormatINR(calc.perDay)}\nEarned:        ${esFormatINR(calc.earned)}\nDeduction:    -${esFormatINR(calc.deduction)}\n${'─'.repeat(40)}\nNET SALARY:    ${esFormatINR(calc.net)}\n${'='.repeat(40)}`;
  const a = document.createElement('a');
  a.href = 'data:text/plain;charset=utf-8,' + encodeURIComponent(txt);
  a.download = `PaySlip_${emp.name}_${monthName}.txt`;
  a.click();
}

function esExportAttendance(){
  const month = Number(document.getElementById('es-att-month')?.value ?? new Date().getMonth());
  const year = Number(document.getElementById('es-att-year')?.value ?? new Date().getFullYear());
  const days = esDaysInMonth(year, month);
  let csv = 'Employee,Category,Shift,' + Array.from({length:days},(_,i)=>i+1).join(',') + ',Present,Absent\n';
  esEmployees.forEach(emp=>{
    const shifts = emp.shift === 'all' ? ['morning','afternoon','night'] : [emp.shift];
    shifts.forEach(sh=>{
      let presentCount = 0;
      const row = [emp.name, emp.category, ES_SHIFTS[sh]?.label || sh];
      for(let d=1;d<=days;d++){
        const date = year+'-'+String(month+1).padStart(2,'0')+'-'+String(d).padStart(2,'0');
        const val = esAttendance[esAttKey(emp.id,date,sh)] || '';
        row.push(val ? val.toUpperCase().charAt(0) : '');
        if(val==='present'||val==='late') presentCount++;
        else if(val==='half') presentCount+=0.5;
      }
      row.push(presentCount, Math.max(0, (emp.workDays||26)-presentCount));
      csv += row.join(',') + '\n';
    });
  });
  const a = document.createElement('a');
  a.href = 'data:text/csv;charset=utf-8,' + encodeURIComponent(csv);
  a.download = `Attendance_${year}_${String(month+1).padStart(2,'0')}.csv`;
  a.click();
  showToast(_si(28) + ' Attendance CSV downloaded!', 'success');
}

function esExportSalaryCSV(){
  const month = Number(document.getElementById('es-sal-month')?.value ?? new Date().getMonth());
  const year = Number(document.getElementById('es-sal-year')?.value ?? new Date().getFullYear());
  const monthName = new Date(year,month).toLocaleString('default',{month:'long',year:'numeric'});
  let csv = `Salary Sheet — ${monthName}\nName,Category,Base Salary,Days Present,Working Days,Deduction,Net Salary,Status\n`;
  esEmployees.forEach(emp=>{
    const calc = esCalcSalary(emp,year,month);
    const paid = esSalaryStatus[esSalKey(emp.id,year,month)] === 'paid' ? 'Paid' : 'Pending';
    csv += `${emp.name},${emp.category},${emp.salary},${calc.daysPresent},${calc.workDays},${calc.deduction},${calc.net},${paid}\n`;
  });
  const a = document.createElement('a');
  a.href = 'data:text/csv;charset=utf-8,' + encodeURIComponent(csv);
  a.download = `Salary_${year}_${String(month+1).padStart(2,'0')}.csv`;
  a.click();
  showToast(_si(28) + ' Salary CSV downloaded!', 'success');
}

document.addEventListener('DOMContentLoaded', function(){
  const origSP3 = window.showPage;
  window.showPage = function(page, el){
    origSP3 && origSP3(page, el);
    if(page === 'esalary') setTimeout(esInit, 100);
    if(page === 'daily-owner-report') odwsInit();
    if(page === 'staff-performance') wptInit();
    if(page === 'smart-reorder') airInit();
  };
  const now = new Date();
  ['es-month-sel','es-att-month','es-sal-month','es-ps-month'].forEach(id=>{
    const el = document.getElementById(id);
    if(el) el.value = String(now.getMonth());
  });
});

function odwsInit(){ /* init: nothing needed, generate on demand */ }

function odwsGenerate(){
  const now = new Date();
  const dateStr = now.toLocaleDateString('en-IN',{weekday:'long',day:'2-digit',month:'long',year:'numeric'});
  const revenue = document.getElementById('dash-revenue')?.textContent || '84,200';
  const lang = document.getElementById('odws-lang')?.value || 'hindi';

  const t1 = document.getElementById('odws-t1')?.classList.contains('on');
  const t2 = document.getElementById('odws-t2')?.classList.contains('on');
  const t3 = document.getElementById('odws-t3')?.classList.contains('on');
  const t4 = document.getElementById('odws-t4')?.classList.contains('on');
  const t5 = document.getElementById('odws-t5')?.classList.contains('on');
  const t6 = document.getElementById('odws-t6')?.classList.contains('on');
  const t7 = document.getElementById('odws-t7')?.classList.contains('on');

  let msg = `*${_si(11)}️ Siplora — Daily Restaurant Summary*\n${_si(25)} ${dateStr}\n${'─'.repeat(32)}\n`;

  if(t1) msg += `\n*${_si(27)} Revenue Today*\n• Total Revenue: ₹${revenue}\n• Orders Completed: 47\n• Avg. Bill Value: ₹1,791\n• Payment Modes: Cash 40% | UPI 45% | Card 15%\n`;

  if(t2) msg += `\n*${_si(11)}️ Top Selling Dishes*\n1. ${_si(56)} Butter Chicken — 47 plates\n2. ${_si(56)} Biryani — 38 plates\n3. ${_si(56)} Paneer Tikka — 29 plates\n`;

  if(t3) msg += `\n*${_si(26)} Staff Attendance*\n• Present: 18/20\n• Absent: Sneha Joshi (Notified)\n• Late Arrivals: 1 (Rahul — 15 min)\n`;

  if(t4) msg += `\n*${_si(8)} Low Stock Alerts ${_si(18)}️*\n• Paneer: 8 Kg (Min: 15 Kg) — ORDER NEEDED\n• Ghee: 5 L (Min: 8 L) — ORDER NEEDED\n• Tomatoes: 12 Kg — Medium\n`;

  if(t5) msg += `\n*${_si(86)} Pending Tasks*\n• Deep clean kitchen (Ravi — DUE)\n• Order supplies (Priya — OVERDUE ${_si(18)}️)\n• Inventory count (Amit — In Progress)\n`;

  if(t6) msg += `\n*${_si(1)} Customer Ratings Today*\n• Avg Rating: 4.3 / 5\n• 5-Star Reviews: 8\n• Complaints: 2 (Resolved: 1)\n`;

  if(t7) msg += `\n*${_si(82)} Salary Status (This Month)*\n• Total Payroll: ₹2,17,000\n• Paid: 3 employees\n• Pending: 2 employees\n`;

  msg += `\n${'─'.repeat(32)}\n${_si(38)} Siplora AI POS System\n_Auto-generated at ${now.toLocaleTimeString('en-IN',{hour:'2-digit',minute:'2-digit'})}_`;

  document.getElementById('odws-preview').textContent = msg;
  showToast(_si(28) + ' Summary generated!','success');
}

function odwsSendNow(){
  const preview = document.getElementById('odws-preview').textContent;
  if(!preview || preview.includes('generate karne ke liye')){ showToast('Pehle "Generate & Preview" dabao!','warning'); return; }
  const phone = document.getElementById('odws-phone').value.replace(/\D/g,'');
  if(!phone){ showToast('Owner phone number daalo!','warning'); return; }
  const url = `https://wa.me/${phone}?text=${encodeURIComponent(preview)}`;
  window.open(url,'_blank');
  showToast(_si(87) + ' WhatsApp opened — Send the message!','success');
  const tbody = document.getElementById('odws-history-tbody');
  if(tbody){
    const now = new Date();
    const row = tbody.insertRow(0);
    row.innerHTML = `<td>${now.toLocaleDateString('en-IN',{day:'2-digit',month:'short',year:'numeric'})}</td><td>${now.toLocaleTimeString('en-IN',{hour:'2-digit',minute:'2-digit'})}</td><td style="color:var(--gold-light)">₹${document.getElementById('dash-revenue')?.textContent||'—'}</td><td>47</td><td>18/20</td><td><span class="badge badge-green">Sent ${_si(28)}</span></td><td><button class="btn btn-ghost btn-sm" onclick="odwsResend(this)">${_si(88)} Resend</button></td>`;
  }
}

function odwsResend(btn){ btn.closest('tr').querySelector('td:nth-child(6)').innerHTML='<span class="badge badge-blue">Resending...</span>'; setTimeout(()=>{ btn.closest('tr').querySelector('td:nth-child(6)').innerHTML='<span class="badge badge-green">Sent '+_si(28)+'</span>'; showToast('Summary resend kiya gaya!','success'); },800); }

function odwsCopy(){
  const text = document.getElementById('odws-preview').textContent;
  if(!text || text.includes('generate karne ke liye')){ showToast('Please generate first!','warning'); return; }
  navigator.clipboard.writeText(text).then(()=>showToast(_si(24) + ' Copied to clipboard!','success')).catch(()=>showToast('Copy failed — please select manually','error'));
}

function odwsSaveSettings(){ showToast(_si(28) + ' Settings saved!','success'); }

function odwsAutoSchedule(){
  const t = document.getElementById('odws-time')?.value || '22:00';
  showToast(`${_si(50)} Auto-send scheduled at ${t} daily! (WhatsApp API lagega)`, 'info');
}

const wptData = {
  waiters: [
    { id:'priya', name:'Priya Sharma', orders:14, rating:4.8, tips:540, complaints:0, tables:14 },
    { id:'rahul', name:'Rahul Verma',  orders:10, rating:3.9, tips:380, complaints:1, tables:10 },
    { id:'sneha', name:'Sneha Joshi',  orders:9,  rating:4.1, tips:320, complaints:1, tables:9  },
    { id:'pooja', name:'Pooja Singh',  orders:8,  rating:4.5, tips:270, complaints:0, tables:8  },
    { id:'arjun', name:'Arjun Das',    orders:6,  rating:4.2, tips:200, complaints:0, tables:6  },
  ]
};

function wptScore(w){ return Math.round(w.orders * 0.4 + w.rating * 20 + w.tips/100 - w.complaints * 5); }

function wptInit(){ wptRenderLeaderboard(); wptLoadDetail(); }

function wptRenderLeaderboard(){
  const box = document.getElementById('wpt-leaderboard-cards'); if(!box) return;
  const sorted = [...wptData.waiters].sort((a,b)=>wptScore(b)-wptScore(a));
  const medals = [''+_si(56)+'',''+_si(56)+'',''+_si(56)+'','4️⃣','5️⃣'];
  box.innerHTML = sorted.map((w,i)=>{
    const score = wptScore(w);
    const barW = Math.round((score / wptScore(sorted[0]))*100);
    const ratingStars = ''+_si(1)+''.repeat(Math.round(w.rating));
    return `<div style="display:flex;align-items:center;gap:14px;padding:14px;background:${i===0?'rgba(201,168,76,0.08)':'var(--glass)'};border:1px solid ${i===0?'rgba(201,168,76,0.3)':'var(--glass-border)'};border-radius:12px;transition:all 0.3s">
      <div style="font-size:28px;flex-shrink:0">${medals[i]}</div>
      <div style="flex:1;min-width:0">
        <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:6px">
          <div style="font-family:var(--font-ui);font-size:14px;color:var(--cream)">${w.name}</div>
          <div style="font-family:var(--font-royal);font-size:20px;color:var(--gold-light)">${score} pts</div>
        </div>
        <div class="progress-bar"><div class="progress-fill" style="width:${barW}%"></div></div>
        <div style="display:flex;gap:16px;margin-top:8px;flex-wrap:wrap">
          <span style="font-family:var(--font-ui);font-size:10px;color:rgba(245,240,232,0.5)">${_si(24)} Orders: <b style="color:var(--cream)">${w.orders}</b></span>
          <span style="font-family:var(--font-ui);font-size:10px;color:rgba(245,240,232,0.5)">${ratingStars} <b style="color:var(--cream)">${w.rating}</b></span>
          <span style="font-family:var(--font-ui);font-size:10px;color:rgba(245,240,232,0.5)">${_si(27)} Tips: <b style="color:var(--gold-light)">₹${w.tips}</b></span>
          ${w.complaints>0?`<span style="font-family:var(--font-ui);font-size:10px;color:#e74c3c">${_si(86)} Complaints: ${w.complaints}</span>`:''}
        </div>
      </div>
      <button class="btn btn-ghost btn-sm" onclick="wptSendBonus('${w.name}')">${_si(74)} Bonus</button>
    </div>`;
  }).join('');
  if(sorted.length){ document.getElementById('wpt-top-waiter').textContent = sorted[0].name.split(' ')[0]; }
}

function wptLoadDetail(){
  const box = document.getElementById('wpt-detail-kpis'); if(!box) return;
  const wId = document.getElementById('wpt-detail-waiter')?.value || 'priya';
  const w = wptData.waiters.find(x=>x.id===wId) || wptData.waiters[0];
  box.innerHTML = `
    <div class="stat-card" style="--accent-color:#3498db"><div style="font-size:18px">${_si(24)}</div><div class="stat-value">${w.orders}</div><div class="stat-label">Orders This Period</div></div>
    <div class="stat-card" style="--accent-color:#c9a84c"><div style="font-size:18px">${_si(1)}</div><div class="stat-value">${w.rating}</div><div class="stat-label">Avg Rating</div></div>
    <div class="stat-card" style="--accent-color:#2ecc71"><div style="font-size:18px">${_si(27)}</div><div class="stat-value">₹${w.tips}</div><div class="stat-label">Total Tips</div></div>`;

  const chart = document.getElementById('wpt-orders-chart'); if(!chart) return;
  const vals=[3,5,4,6,4,7,5,4,3,6,5,4,3,5,4,3,6,5,4,3];
  const max=Math.max(...vals);
  chart.innerHTML = vals.map(v=>`<div style="flex:1;height:${Math.round((v/max)*100)}%;background:linear-gradient(180deg,var(--gold-light),var(--gold-dim));border-radius:3px 3px 0 0;min-height:3px;transition:height 0.8s" title="${v} orders"></div>`).join('');
}

function wptSaveTip(){
  const waiter = document.getElementById('wpt-tip-waiter')?.value;
  const amt = document.getElementById('wpt-tip-amt')?.value;
  const table = document.getElementById('wpt-tip-table')?.value;
  if(!amt||amt<=0){ showToast('Tip amount daalo!','warning'); return; }
  const w = wptData.waiters.find(x=>x.name===waiter);
  if(w){ w.tips += parseInt(amt); }
  document.getElementById('wpt-tip-amt').value='';
  document.getElementById('wpt-tip-table').value='';
  document.getElementById('wpt-total-tips').textContent = '₹'+(wptData.waiters.reduce((s,x)=>s+x.tips,0));
  showToast(`${_si(28)} ₹${amt} tip added for ${waiter}!`,'success');
}

