function airSendOrder(item, supplier, qty){
  const supplierPhones = { 'Amul':'+919876500001','Fresh Farms':'+919876500002','Local Market':'+919876500003','Royal Rice':'+919876500004','Dairy Direct':'+919876500005' };
  const phone = supplierPhones[supplier] || '';
  const now = new Date();
  const msg = `*${_si(8)} Stock Reorder Request*\n\nRestaurant: Siplora\nDate: ${now.toLocaleDateString('en-IN')}\nTime: ${now.toLocaleTimeString('en-IN',{hour:'2-digit',minute:'2-digit'})}\n\nItem: *${item}*\nQty Required: *${qty}*\n\nPlease deliver at the earliest.\n\n${_si(38)} Siplora Restaurant\n${_si(23)} 9021758399`;
  if(phone){
    window.open(`https://wa.me/${phone.replace(/\D/g,'')}?text=${encodeURIComponent(msg)}`,'_blank');
  } else {
    alert('Supplier phone number not found. Please add it in the Supplier Map!');
    return;
  }
  const tbody = document.getElementById('air-orders-tbody');
  if(tbody){
    const row = tbody.insertRow(0);
    row.innerHTML = `<td>${now.toLocaleDateString('en-IN')} ${now.toLocaleTimeString('en-IN',{hour:'2-digit',minute:'2-digit'})}</td><td>${item}</td><td>${qty}</td><td>${supplier}</td><td><span class="badge badge-purple">${_si(19)} Manual</span></td><td><span class="badge badge-green">Sent ${_si(28)}</span></td><td><span class="badge badge-gold">Pending Delivery</span></td>`;
  }
  showToast(`${_si(28)} ${item} ka order ${supplier} set to bheja gaya!`,'success');
}

