function payRenderHistory(){
  const tbody = document.getElementById('pay-hist-tbody'); if(!tbody) return;
  const dateFilter = document.getElementById('pay-hist-date')?.value||'';
  const statusFilter = document.getElementById('pay-hist-status')?.value||'all';
  let data = payLoad();
  if(dateFilter) data = data.filter(t=>t.date===new Date(dateFilter).toLocaleDateString('en-IN'));
  if(statusFilter!=='all') data = data.filter(t=>t.status===statusFilter);
  if(!data.length){ tbody.innerHTML='<tr><td colspan="8" style="text-align:center;color:rgba(245,240,232,0.3);padding:24px">No transactions found</td></tr>'; return; }
  const statusBadge = {success:'badge-green',pending:'badge-gold',failed:'badge-red',refunded:'badge-purple'};
  tbody.innerHTML = [...data].reverse().map((t,i)=>`
    <tr>
      <td style="font-family:var(--font-ui);font-size:10px;color:var(--gold)">${t.id}</td>
      <td>${t.date} ${t.time}</td>
      <td>${t.name}</td>
      <td style="color:#2ecc71;font-family:var(--font-royal);font-size:16px">₹${t.amount.toLocaleString('en-IN')}</td>
      <td><span class="badge badge-blue">${t.method}</span></td>
      <td style="font-family:var(--font-ui);font-size:10px;color:rgba(245,240,232,0.4)">${t.txnId||'—'}</td>
      <td><span class="badge ${statusBadge[t.status]||'badge-gold'}">${t.status}</span></td>
      <td>
        <select onchange="payUpdatePaymentStatus('${t.id}',this.value)" style="background:var(--dark3);border:1px solid var(--glass-border);color:var(--cream);border-radius:6px;padding:4px 8px;font-size:10px;cursor:pointer">
          <option ${t.status==='success'?'selected':''} value="success">Success</option>
          <option ${t.status==='pending'?'selected':''} value="pending">Pending</option>
          <option ${t.status==='failed'?'selected':''} value="failed">Failed</option>
          <option ${t.status==='refunded'?'selected':''} value="refunded">Refunded</option>
        </select>
      </td>
    </tr>`).join('');
}

function payUpdateStats(){
  const data = payLoad();
  const today = new Date().toLocaleDateString('en-IN');
  const todayData = data.filter(t=>t.date===today&&t.status==='success');
  const total = todayData.reduce((s,t)=>s+t.amount,0);
  const allToday = data.filter(t=>t.date===today);
  const pending = allToday.filter(t=>t.status==='pending').length;
  const digital = todayData.length;
  setEl('pay-today-total','₹'+total.toLocaleString('en-IN'));
  setEl('pay-txn-count', digital);
  setEl('pay-pending-count', pending);
  setEl('pay-digital-pct', allToday.length>0?Math.round(digital/allToday.length*100)+'%':'0%');
}

function payReconGenerate(){
  const data = payLoad();
  const dateInput = document.getElementById('pay-recon-date')?.value;
  const filterDate = dateInput ? new Date(dateInput).toLocaleDateString('en-IN') : new Date().toLocaleDateString('en-IN');
  const todayData = data.filter(t=>t.date===filterDate&&t.status==='success');
  const cash = todayData.filter(t=>['Cash'].includes(t.method)).reduce((s,t)=>s+t.amount,0);
  const upi = todayData.filter(t=>['UPI','GPay','PhonePe','Paytm','BHIM'].includes(t.method)).reduce((s,t)=>s+t.amount,0);
  const card = todayData.filter(t=>['Card','Net Banking'].includes(t.method)).reduce((s,t)=>s+t.amount,0);
  const total = cash+upi+card;
  const fmt=v=>'₹'+v.toLocaleString('en-IN');
  setEl('rec-cash', fmt(cash));
  setEl('rec-upi', fmt(upi));
  setEl('rec-card', fmt(card));
  setEl('rec-total', fmt(total));
}

