function payPrintQR(){ window.print(); }

function paySaveSettings(){ showToast(_si(28) + ' Payment settings saved!','success'); }

function payExportCSV(){
  const data = payLoad();
  let csv='ID,Date,Time,Customer,Amount,Method,TxnID,Status\n';
  data.forEach(t=>{ csv+=`${t.id},${t.date},${t.time},"${t.name}",${t.amount},${t.method},${t.txnId||''},${t.status}\n`; });
  const a=document.createElement('a'); a.href='data:text/csv;charset=utf-8,'+encodeURIComponent(csv); a.download='Payment_Transactions.csv'; a.click();
  showToast(_si(92) + ' Transactions CSV exported!','success');
}

function payReconExport(){
  showToast(_si(30) + ' Generating reconciliation PDF...','info');
  const fmt=v=>'Rs.'+v.toLocaleString('en-IN');
  setTimeout(()=>{
    const win=window.open('','_blank');
    win.document.write(`<html><head><title>Payment Reconciliation</title><style>body{font-family:sans-serif;padding:32px;background:#fff;color:#111}h1{text-align:center}table{width:100%;border-collapse:collapse;margin-top:16px}th,td{padding:10px 14px;border:1px solid #ddd;text-align:left}th{background:#f5f5f5}.total{font-weight:bold}<\/style><\/head><body>`);
    win.document.write(`<h1>Siplora — Daily Payment Reconciliation</h1>`);
    win.document.write(`<table><tr><th>Type</th><th>Amount</th></tr><tr><td>Cash</td><td>${fmt(0)}</td></tr><tr><td>UPI / Digital</td><td>${fmt(0)}</td></tr><tr><td>Card</td><td>${fmt(0)}</td></tr><tr class="total"><td>Grand Total</td><td>${fmt(0)}</td></tr></table>`);
    win.document.write('<\/body><\/html>');
    win.document.close(); win.print();
  },500);
}

function payReconWA(){
  const msg=`*${_si(99)} Daily Payment Reconciliation — Siplora*\n\n${_si(25)} Date: ${new Date().toLocaleDateString('en-IN')}\n\n${_si(99)} Cash: *₹${0}*\n${_si(87)} UPI/Digital: *₹${0}*\n${_si(99)} Card: *₹${0}*\n\n${_si(95)} *Grand Total: ₹${0}*\n\n${_si(38)} Siplora Restaurant`;
  window.open('https://wa.me/9021758399?text='+encodeURIComponent(msg),'_blank');
}

