let todActiveCat = 'all';
let todSlideState = {}; // { offerId: currentSlideIndex }
let todTimers = {};
let todInquiries = JSON.parse(localStorage.getItem(window._sipKey('tod_inq'))||'[]');

function todGetData(){ return TOD_SAMPLE_DATA; }

function todGetCats(){
  const data = todGetData();
  const map = {};
  data.forEach(o=>{
    if(!map[o.cat]){
      let emoji = '', name = o.cat;
      const trimmed = (o.cat||'').trimStart();
      if(trimmed.startsWith('<svg')){
        const svgEnd = o.cat.indexOf('</svg>');
        if(svgEnd !== -1){
          emoji = o.cat.slice(0, svgEnd + 6);
          name = o.cat.slice(svgEnd + 6).trim();
        } else {
          const gtIdx = o.cat.indexOf('>');
          emoji = o.cat.slice(0, gtIdx + 1);
          name = o.cat.slice(gtIdx + 1).trim();
        }
      } else {
        emoji = o.icon || '';
        name = o.cat;
      }
      map[o.cat] = {count:0, emoji:emoji, name:name, catKey:o.catKey};
    }
    map[o.cat].count++;
  });
  return map;
}

function todInit(){
  todUpdateStats();
  todRenderCats();
  todRender();
}

function todUpdateStats(){
  const data = todGetData();
  const cats = new Set(data.map(o=>o.cat));
  const shops = new Set(data.map(o=>o.shop));
  const today = new Date().toLocaleDateString('en-IN');
  const inqToday = todInquiries.filter(i=>i.date===today).length;
  const el = id=>document.getElementById(id);
  if(el('tod-stat-offers')) el('tod-stat-offers').textContent = data.length;
  if(el('tod-stat-cats')) el('tod-stat-cats').textContent = cats.size;
  if(el('tod-stat-shops')) el('tod-stat-shops').textContent = shops.size;
  if(el('tod-stat-inq')) el('tod-stat-inq').textContent = inqToday;
}

function todRenderCats(){
  const grid = document.getElementById('tod-cat-grid');
  if(!grid) return;
  const cats = todGetCats();
  const allCount = todGetData().length;
  let html = `<div class="tod-cat-card ${todActiveCat==='all'?'selected':''}" onclick="todSetCat('all')">
    <span class="tod-cat-emoji">${_si(107)}</span>
    <div class="tod-cat-name">Sabhi</div>
    <div class="tod-cat-count">${allCount}</div>
  </div>`;
  Object.entries(cats).forEach(([cat,info])=>{
    const sel = todActiveCat===info.catKey?'selected':'';
    html += `<div class="tod-cat-card ${sel}" onclick="todSetCat('${info.catKey}')">
      <span class="tod-cat-emoji">${info.emoji}</span>
      <div class="tod-cat-name">${info.name}</div>
      <div class="tod-cat-count">${info.count}</div>
    </div>`;
  });
  grid.innerHTML = html;
}

function todSetCat(cat){
  todActiveCat = cat;
  todRenderCats();
  const title = document.getElementById('tod-panel-title');
  const sub = document.getElementById('tod-panel-sub');
  if(title) title.textContent = cat==='all' ? _si(108) + '️ Sabhi Offers' : cat+' ke Offers';
  if(sub) sub.textContent = 'Neeche ke cards mein offers dekho — call/WhatsApp/message kar sakte ho';
  todRender();
}

function todStars(r){
  const full = Math.floor(r), half = r%1>=0.5;
  return '<svg xmlns=\"http://www.w3.org/2000/svg\" width=\"1em\" height=\"1em\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\" style=\"display:inline-block;vertical-align:-0.15em;flex-shrink:0\" ><polygon points=\"12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2\"/></svg>'.repeat(full)+(half?'½':'')+'<svg xmlns=\"http://www.w3.org/2000/svg\" width=\"1em\" height=\"1em\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\" style=\"display:inline-block;vertical-align:-0.15em;flex-shrink:0\" ><polygon points=\"12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2\"/></svg>'.repeat(5-full-(half?1:0));
}

function todDist(km){
  if(!km||km<=0) return '';
  const mins = Math.round(km/0.35); // walking ~1.2km/h... use driving ~30km/h
  const drive = Math.round(km/0.5);
  return `${km} km · ~${drive} min drive`;
}

function todRender(){
  const grid = document.getElementById('tod-offers-grid');
  if(!grid) return;
  const search = (document.getElementById('tod-search')?.value||'').toLowerCase();
  let data = todGetData();
  if(todActiveCat!=='all') data = data.filter(o=>o.catKey===todActiveCat);
  if(search) data = data.filter(o=>
    o.shop.toLowerCase().includes(search)||
    o.discount.toLowerCase().includes(search)||
    o.cat.toLowerCase().includes(search)||
    (o.offer||'').toLowerCase().includes(search)
  );
  if(!data.length){
    grid.innerHTML=`<div class="tod-empty"><div class="big">${_si(41)}</div><div class="title">Koi offer nahi mila</div><div class="sub">Doosri category try karo</div></div>`;
    return;
  }

  Object.values(todTimers).forEach(t=>clearInterval(t));
  todTimers = {};

  grid.innerHTML = data.map(o=>{
    if(!(o.id in todSlideState)) todSlideState[o.id]=0;
    const cur = todSlideState[o.id];
    const hasSlides = o.slides&&o.slides.length>0;
    const slideCount = hasSlides ? o.slides.length : 1;

    const slidesHTML = hasSlides ? o.slides.map((src,i)=>{
      const isVideo = src.match(/\.(mp4|webm|ogg)/i);
      const mediaTag = isVideo
        ? `<video src="${src}" muted loop playsinline></video>`
        : `<img src="${src}" alt="${o.shop}" loading="lazy" onerror="this.style.display='none';" />`;
      return `<div class="tod-slide ${i===cur?'on':''}" data-idx="${i}">${mediaTag}</div>`;
    }).join('') : `<div class="tod-slide on"><div class="tod-slide-empty"><span style="font-size:56px">${o.cat.split(' ')[0]}</span><div style="font-family:var(--font-royal);font-size:17px;color:rgba(245,240,232,0.5);margin-top:10px">${o.shop}</div></div></div>`;

    const dotsHTML = slideCount>1 ? `<div class="tod-dots">${o.slides.map((_,i)=>`<button class="tod-dot ${i===cur?'on':''}" onclick="todGoSlide('${o.id}',${i});event.stopPropagation()"></button>`).join('')}</div>` : '';

    const typeLabel = o.type==='service' ? 'SERVICE' : 'SHOP';
    const validText = o.validTill ? new Date(o.validTill).toLocaleDateString('en-IN') : 'Limited Time';

    const svcHTML = o.services&&o.services.length ? o.services.map(s=>`<span style="display:inline-flex;align-items:center;gap:4px;background:rgba(201,168,76,0.08);border:1px solid rgba(201,168,76,0.15);border-radius:20px;padding:3px 10px;font-family:var(--font-ui);font-size:9px;color:var(--gold-light);margin:2px">${_si(28)} ${s}</span>`).join('') : '';

    return `<div class="tod-offer-card" id="tod-card-${o.id}">
      <div class="tod-slide-box">
        ${slidesHTML}
        ${dotsHTML}
        <div class="tod-discount-tag">${o.discount}</div>
        <div class="tod-type-tag">${typeLabel}</div>
      </div>
      <div class="tod-body">
        <div class="tod-shop-row">
          <div class="tod-shop-name">${o.shop}</div>
          <div class="tod-rating"><span class="tod-stars">${todStars(o.rating)}</span><span class="tod-rnum">${o.rating}</span></div>
        </div>
        <div style="margin-bottom:8px"><span style="display:inline-block;background:rgba(255,107,53,0.08);border:1px solid rgba(255,107,53,0.2);border-radius:20px;padding:2px 10px;font-family:var(--font-ui);font-size:8px;letter-spacing:1px;color:#ff9a6c">${o.cat}</span></div>
        <div class="tod-offer-hl">${_si(74)} ${o.discount}</div>
        <div class="tod-info-row" style="margin-bottom:4px">${o.address?`<span>${_si(73)}</span><span class="val" style="font-size:10px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;max-width:220px">${o.address}</span>`:''}</div>
        <div class="tod-info-row" style="margin-bottom:8px">${o.dist?`<span>${_si(70)}</span><span class="val" style="font-size:10px">${todDist(o.dist)} door</span>`:''}</div>

        <!-- READ MORE SECTION (hidden by default) -->
        <div class="tod-extra" id="tod-extra-${o.id}">
          ${o.offer?`<div style="font-family:var(--font-ui);font-size:11px;color:rgba(245,240,232,0.75);line-height:1.6;margin-bottom:10px;padding:8px 12px;background:rgba(255,107,53,0.06);border-radius:8px;border-left:2px solid #ff6b35">${o.offer}</div>`:''}
          ${o.timings?`<div class="tod-info-row"><span>${_si(50)}</span><span class="val">${o.timings}</span></div>`:''}
          <div class="tod-info-row"><span>${_si(23)}</span><span class="val">${o.phone}</span></div>
          ${o.about?`<div class="tod-extra-row" style="color:rgba(245,240,232,0.65);margin:8px 0;font-size:10px;line-height:1.6">${o.about}</div>`:''}
          ${svcHTML?`<div style="margin-top:8px;display:flex;flex-wrap:wrap;gap:4px">${svcHTML}</div>`:''}
          <div class="tod-valid-row"><span>${_si(17)} Valid till: ${validText}</span><span>${o.type==='service'?_si(101) + ' Service':_si(71) + ' Shop'}</span></div>
        </div>

        <button class="tod-more-btn" onclick="todToggleMore('${o.id}',this)">${_si(109)} Read More ▼</button>

        <div class="tod-actions">
          <button class="tod-btn tod-call" onclick="todCall('${o.phone}','${o.id}')">${_si(78)} Call</button>
          <button class="tod-btn tod-wa" onclick="todWA('${o.whatsapp}','${o.shop}','${o.discount}','${o.id}')">${_si(54)} WA</button>
          <button class="tod-btn tod-sms" onclick="todSMS('${o.phone}','${o.id}')">${_si(110)} Msg</button>
        </div>
      </div>
    </div>`;
  }).join('');

  data.forEach(o=>{
    if(o.slides&&o.slides.length>1){
      todTimers[o.id] = setInterval(()=>{
        const next = (todSlideState[o.id]+1)%o.slides.length;
        todGoSlide(o.id, next);
      }, 3500);
    }
  });
}

function todGoSlide(offerId, idx){
  todSlideState[offerId] = idx;
  const card = document.getElementById('tod-card-'+offerId);
  if(!card) return;
  card.querySelectorAll('.tod-slide').forEach((s,i)=>s.classList.toggle('on',i===idx));
  card.querySelectorAll('.tod-dot').forEach((d,i)=>d.classList.toggle('on',i===idx));
  const activeVid = card.querySelectorAll('.tod-slide')[idx]?.querySelector('video');
  if(activeVid) activeVid.play().catch(()=>{});
}

function todToggleMore(id, btn){
  const el = document.getElementById('tod-extra-'+id);
  if(!el) return;
  const open = el.classList.toggle('open');
  btn.innerHTML = open ? _si(109) + ' Read Less ▲' : _si(109) + ' Read More ▼';
}

function todCall(phone, id){
  todLogInq(id,'call');
  window.open('tel:'+phone.replace(/\s/g,''),'_self');
  showToast(_si(23) + ' Calling...','success');
}

function todWA(num, shop, disc, id){
  todLogInq(id,'whatsapp');
  const clean = num.replace(/\D/g,'');
  const msg = encodeURIComponent(`Hello! I saw your "${disc}" offer. I would like to make a deal with "${shop}". Can you please provide more details?`);
  window.open(`https://wa.me/${clean}?text=${msg}`,'_blank');
  showToast(_si(54) + ' Opening WhatsApp...','success');
}

function todSMS(phone, id){
  todLogInq(id,'sms');
  window.open('sms:'+phone.replace(/\s/g,''),'_self');
  showToast(_si(110) + ' Opening message app...','info');
}

function todLogInq(offerId, type){
  todInquiries.push({offerId,type,date:new Date().toLocaleDateString('en-IN'),time:new Date().toLocaleTimeString('en-IN')});
  localStorage.setItem(window._sipKey('tod_inq'),JSON.stringify(todInquiries));
  todUpdateStats();
}

