let rekActiveCat = 'all';
let rekCurrentProfile = null;

function rekInit(){
  REK_CATEGORIES.forEach(c => {
    c.count = c.id === 'all' ? REK_PROFILES.length : REK_PROFILES.filter(p => p.cat === c.id).length;
  });
  rekRenderCats();
  rekFilter();
  rekUpdateStats();
}

function rekRenderCats(){
  const grid = document.getElementById('rek-cat-grid');
  if(!grid) return;
  grid.innerHTML = REK_CATEGORIES.map(c => `
    <div class="rek-cat-btn ${c.id===rekActiveCat?'active':''}" onclick="rekSetCat('${c.id}')">
      <span class="rek-cat-emoji">${c.emoji}</span>
      <div class="rek-cat-name">${c.name}</div>
      <div class="rek-cat-count">${c.count}</div>
    </div>`).join('');
}

function rekSetCat(id){
  rekActiveCat = id;
  rekRenderCats();
  rekFilter();
}

function rekFilter(){
  const q = (document.getElementById('rek-search')?.value||'').toLowerCase();
  const avail = document.getElementById('rek-avail-filter')?.value||'';
  const expF = document.getElementById('rek-exp-filter')?.value||'';
  let profiles = REK_PROFILES.filter(p => {
    if(rekActiveCat !== 'all' && p.cat !== rekActiveCat) return false;
    if(avail && p.availability !== avail) return false;
    if(expF){
      if(expF==='0-1' && !(p.expYrs<=1)) return false;
      if(expF==='1-3' && !(p.expYrs>1 && p.expYrs<=3)) return false;
      if(expF==='3-5' && !(p.expYrs>3 && p.expYrs<=5)) return false;
      if(expF==='5+' && !(p.expYrs>5)) return false;
    }
    if(q){
      const combined = (p.name+p.role+p.skills.join(' ')+p.city+p.about).toLowerCase();
      if(!combined.includes(q)) return false;
    }
    return true;
  });
  rekRenderProfiles(profiles);
}

function rekRenderProfiles(list){
  const grid = document.getElementById('rek-profiles-grid');
  const empty = document.getElementById('rek-empty');
  if(!grid) return;
  if(!list.length){ grid.innerHTML=''; if(empty) empty.style.display='block'; return; }
  if(empty) empty.style.display='none';
  const availColors = {available:'#2ecc71',notice:'#e8cc7e',busy:'#e74c3c'};
  const availLabel = {available:'Available Now',notice:'Notice Period',busy:'Not Available'};
  grid.innerHTML = list.map(p => `
    <div class="rek-card">
      <div class="rek-card-top">
        <div class="rek-avatar">${p.emoji}</div>
        <div style="flex:1;min-width:0">
          <div class="rek-name">${p.name}</div>
          <div class="rek-role">${p.role}</div>
          <div style="margin-top:5px;display:flex;flex-wrap:wrap;gap:5px;align-items:center">
            <span class="rek-exp-badge">${_si(50)} ${p.exp}</span>
            <span class="rek-exp-badge" style="background:rgba(201,168,76,0.08);border-color:rgba(201,168,76,0.25);color:var(--gold-light)">${_si(73)} ${p.city}</span>
          </div>
          <div style="margin-top:6px;display:flex;align-items:center;gap:5px">
            <span class="rek-avail-dot ${p.availability}"></span>
            <span style="font-family:var(--font-ui);font-size:9px;color:${availColors[p.availability]};letter-spacing:1px">${availLabel[p.availability]}</span>
          </div>
        </div>
      </div>
      <div class="rek-card-mid">
        <div class="rek-info-row">
          <span class="rek-info-label">${_si(131)} Education</span>
          <span class="rek-info-val" style="font-size:10px;line-height:1.5">${p.edu}</span>
        </div>
        <div class="rek-info-row">
          <span class="rek-info-label">${_si(99)} Salary</span>
          <span class="rek-info-val" style="color:var(--gold-light);font-size:12px;font-weight:500">${p.salary}</span>
        </div>
        ${p.cert ? `<div class="rek-info-row"><span class="rek-info-label">${_si(52)} Cert</span><span class="rek-info-val" style="font-size:10px;opacity:0.65">${p.cert}</span></div>` : ''}
      </div>
      <div class="rek-skills">
        ${p.skills.slice(0,4).map(s=>`<span class="rek-skill-tag">${s}</span>`).join('')}
        ${p.skills.length>4?`<span class="rek-skill-tag" style="background:rgba(201,168,76,0.08);border-color:rgba(201,168,76,0.2);color:var(--gold)">+${p.skills.length-4} more</span>`:''}
      </div>
      <div class="rek-actions" style="flex-wrap:wrap;gap:6px">
        <button class="rek-btn rek-btn-wa" title="WhatsApp" onclick="rekWA('${p.wa}','${p.name}','${p.role}')"><span style="font-size:14px">${_si(54)}</span></button>
        <button class="rek-btn rek-btn-call" title="Call" onclick="rekCall('${p.phone}')"><span style="font-size:14px">${_si(23)}</span></button>
        <button class="rek-btn rek-btn-email" title="Email" onclick="rekEmail('${p.email}','${p.name}')"><span style="font-size:14px">${_si(110)}️</span></button>
        <button class="rek-btn rek-btn-resume" title="View Resume" onclick="rekViewResume(${p.id})" style="flex:2"><span style="font-size:13px">${_si(30)}</span> Resume</button>
      </div>
    </div>`).join('');
}

function rekUpdateStats(){
  const total = REK_PROFILES.length;
  const avail = REK_PROFILES.filter(p=>p.availability==='available').length;
  const exp5 = REK_PROFILES.filter(p=>p.expYrs>=5).length;
  const cats = new Set(REK_PROFILES.map(p=>p.cat)).size;
  document.getElementById('rek-total-count').textContent = total;
  document.getElementById('rek-avail-count').textContent = avail;
  document.getElementById('rek-exp-count').textContent = exp5;
  document.getElementById('rek-cat-count').textContent = cats;
}

function rekWA(num, name, role){
  const msg = encodeURIComponent(`Namaste ${name}! Aapka profile dekha. Hum ${role} position ke liye interested hain. Kya aap available hain interview ke liye?`);
  window.open(`https://wa.me/${num}?text=${msg}`,'_blank');
  showToast(_si(54) + ' Opening WhatsApp...','success');
}
function rekCall(phone){
  window.open('tel:+91'+phone,'_self');
  showToast(_si(23) + ' Calling...','success');
}
function rekEmail(email, name){
  window.open(`mailto:${email}?subject=Job%20Opportunity%20at%20${encodeURIComponent('Siplora Restaurant')}&body=Dear%20${encodeURIComponent(name)}%2C%0A%0AHum%20aapko%20job%20offer%20karna%20chahte%20hain.`,'_blank');
  showToast(_si(110) + ' Opening email app...','info');
}
