(function(){
  const origSP = window.showPage;
  window.showPage = function(page, el){
    origSP && origSP(page, el);
    if(page === 'rekruters') setTimeout(rekInit, 100);
    if(page === 'dashboard') setTimeout(dashInit, 100);
    if(page === 'analytics') setTimeout(analyticsInit, 100);
  };
})();

let DASH_NOTIFICATIONS = [];

async function buildDashNotificationsFromFirebase() {
  const notifs = [];
  try {
    const orders    = getLiveOrders ? getLiveOrders() : [];
    const customers = getLiveCustomers ? getLiveCustomers() : [];
    const staff     = getLiveStaff ? getLiveStaff() : [];
    const stock     = getLiveStock ? getLiveStock() : [];
    const tasks     = (()=>{ try{ return JSON.parse(localStorage.getItem(window._sipKey('lum_tasks'))||'[]'); }catch(e){return[];} })();
    const now       = new Date();
    const today     = now.toDateString();
    const fmtTime   = d => new Date(d).toLocaleTimeString('en-IN',{hour:'2-digit',minute:'2-digit'});

    const todayOrders = orders.filter(o => {
      const t = o.createdAt||o.timestamp||o.time||o.date;
      if(!t) return false;
      try { const d = (typeof t==='object'&&t.seconds) ? new Date(t.seconds*1000) : new Date(t); return d.toDateString()===today; } catch(e){return false;}
    });
    const pendingOrders = todayOrders.filter(o=>o.status==='pending'||o.status==='preparing'||!o.status);
    const paidOrders    = todayOrders.filter(o=>o.status==='paid'||o.status==='completed');
    const todayRevenue  = paidOrders.reduce((s,o)=>s+(o.totalAmount||o.totalBilled||o.total||o.amount||0),0);

    if(todayOrders.length > 0){
      notifs.push({icon:''+_si(27)+'',title:'Billing',msg:'Aaj '+paidOrders.length+' bills — Total ₹'+todayRevenue.toLocaleString('en-IN'),type:'success',time:'Just now',feature:'billing'});
    }
    if(pendingOrders.length > 0){
      const latest = pendingOrders[pendingOrders.length-1];
      const tableNo = latest.tableNumber||latest.table||'?';
      const pendingMins = latest.createdAt||latest.time ? Math.round((now - new Date((typeof (latest.createdAt||latest.time)==='object'&&(latest.createdAt||latest.time).seconds) ? (latest.createdAt||latest.time).seconds*1000 : (latest.createdAt||latest.time)))/60000) : null;
      notifs.push({icon:''+_si(44)+'',title:'Pending Orders',msg:'Table '+tableNo+' — '+(pendingMins?pendingMins+' min se pending — ':'')+pendingOrders.length+' total pending',type:pendingMins>15?'urgent':'warning',time:'Now',feature:'orders'});
    }

    const lowStockItems = stock.filter(i=>Number(i.qty||i.stock||0)<=Number(i.alert||i.minQty||10));
    if(lowStockItems.length > 0){
      const names = lowStockItems.slice(0,3).map(i=>i.name+' ('+( i.qty||i.stock||0)+' '+(i.unit||'')+')').join(', ');
      notifs.push({icon:''+_si(8)+'',title:'Low Stock Alert',msg:names+(lowStockItems.length>3?' aur '+(lowStockItems.length-3)+' items':''),type:'urgent',time:'Now',feature:'inventory'});
    }

    const activeStaff  = staff.filter(s=>(s.status||'').toLowerCase()==='active');
    const absentStaff  = staff.filter(s=>(s.status||'').toLowerCase()==='absent');
    if(staff.length > 0){
      notifs.push({icon:'⊕',title:'Staff Status',msg:activeStaff.length+' present, '+absentStaff.length+' absent today — '+staff.length+' total',type:absentStaff.length>2?'warning':'info',time:'Today',feature:'staff'});
    }

    const urgentTasks = tasks.filter(t=>t.status==='Pending'&&t.priority==='urgent');
    const pendingTasks = tasks.filter(t=>t.status==='Pending');
    if(pendingTasks.length > 0){
      notifs.push({icon:''+_si(28)+'',title:'Tasks Pending',msg:pendingTasks.length+' tasks pending'+(urgentTasks.length>0?' — '+urgentTasks.length+' urgent!':''),type:urgentTasks.length>0?'urgent':'info',time:'Now',feature:'tasks'});
    }

    const todayMD = String(now.getMonth()+1).padStart(2,'0')+'-'+String(now.getDate()).padStart(2,'0');
    const birthdays = customers.filter(c=>{ if(!c.bday) return false; try{ return c.bday.slice(5)===todayMD; }catch(e){return false;} });
    if(birthdays.length > 0){
      notifs.push({icon:''+_si(53)+'',title:'Birthday Today',msg:birthdays.map(c=>c.name).join(', ')+' — WhatsApp wish bhejo!',type:'success',time:'Today',feature:'birthday'});
    }
    if(customers.length > 0){
      const recentCusts = customers.filter(c=>{ try{ const d=new Date(c.addedAt||c.createdAt||0); return d.toDateString()===today; }catch(e){return false;} });
      if(recentCusts.length>0) notifs.push({icon:''+_si(26)+'',title:'New Customers',msg:'Aaj '+recentCusts.length+' naye customers register hue',type:'success',time:'Today',feature:'customers'});
    }

    if(todayRevenue > 0){
      const profit = Math.round(todayRevenue*0.42);
      notifs.push({icon:''+_si(133)+'',title:'Today P&L',msg:'Aaj revenue ₹'+todayRevenue.toLocaleString('en-IN')+' — Estimated profit ₹'+profit.toLocaleString('en-IN'),type:'success',time:'Live',feature:'daily-pl'});
    }

    if(notifs.length === 0){
      notifs.push({icon:'ℹ️',title:'System Connected',msg:'No activity yet — notifications will appear here when orders arrive',type:'info',time:'Now',feature:'dashboard'});
    }
  } catch(e) {
    console.warn('Notification build error:', e);
    notifs.push({icon:''+_si(18)+'️',title:'Data Load Error',msg:'Cloud se data load nahi ho pa raha — Refresh karo',type:'warning',time:'Now',feature:'dashboard'});
  }
  DASH_NOTIFICATIONS = notifs;
  dashRenderNotifications();
}

