let _smFbDb = null;
async function _smFbInit() {
  if (_smFbDb) return _smFbDb;
  _smFbDb = await window._siploraFirebaseLoad();
  return _smFbDb;
}

async function smLoadFromFirebase() {
  try {
    const db = await _smFbInit();
    const { collection, getDocs, onSnapshot } = { collection: window.__col, getDocs: window.__getDocs, onSnapshot: window.__onSnapshot };
    const snap = await getDocs(window._sipCol(db, 'staff'));
    if (snap.empty) { showToast('No staff found in cloud', 'warning'); return; }
    const loaded = [];
    snap.forEach(d => loaded.push(d.data()));
    if (loaded.length > 0) {
      smStaff = loaded.map(s => _smNormalize(s));
      const maxId = Math.max(...loaded.map(s => Number(s.id) || 0));
      smNextId = maxId + 1;
      smRender();
      if (typeof attRenderSelects === 'function') attRenderSelects();
      showToast(_si(45) + ' ' + loaded.length + ' staff loaded from cloud!', 'success');
    }
    if (!window._smFbListener) {
      window._smFbListener = window.__onSnapshot(window._sipCol(db, 'staff'), (snap2) => {
        const updated = [];
        snap2.forEach(d => updated.push(d.data()));
        if (updated.length > 0) {
          smStaff = updated.map(s => _smNormalize(s));
          const maxId2 = Math.max(...updated.map(s => Number(s.id) || 0));
          smNextId = maxId2 + 1;
          smRender();
          if (typeof attRenderSelects === 'function') attRenderSelects();
        }
      });
    }
  } catch (e) {
    console.warn('SM Firebase load error:', e);
    showToast('Sync failed — showing local data', 'warning');
  }
}

function _smNormalize(s) {
  const out = Object.assign({}, s);
  if (typeof out.present !== 'undefined') {
    out.status = out.present ? 'Active' : 'Absent';
  }
  if (typeof out.status !== 'undefined' && typeof out.present === 'undefined') {
    out.present = (out.status === 'Active');
  }
  return out;
}

async function smSaveToFirebase(staffObj) {
  try {
    const db = await _smFbInit();
    const doc = window.__doc; const setDoc = window.__setDoc;
    await setDoc(doc(db, 'staff', String(staffObj.id)), staffObj);
    return true;
  } catch (e) {
    console.warn('SM Firebase save error:', e);
    return false;
  }
}

async function smDeleteFromFirebase(id) {
  try {
    const db = await _smFbInit();
    const doc = window.__doc; const deleteDoc = window.__deleteDoc;
    await deleteDoc(doc(db, 'staff', String(id)));
  } catch (e) {
    console.warn('SM Firebase delete error:', e);
  }
}

