window._sipCouponsCache = window._sipCouponsCache || [];
window._couponFbInited = false;

async function initFirebaseCouponSync(){
  if(window._couponFbInited) return;
  window._couponFbInited = true;
  try {
    const db2 = await window._siploraFirebaseLoad();
    if(!db2) return;
    const { collection, onSnapshot, doc, setDoc, deleteDoc, updateDoc } = { collection: window.__col, onSnapshot: window.__onSnapshot, doc: window.__doc, setDoc: window.__setDoc, deleteDoc: window.__deleteDoc, updateDoc: window.__updateDoc };
    const firebaseConfig = {
      apiKey:"AIzaSyBsRxWD2R1GkSEM-duLwQe3jAi7yw5vvvM",
      authDomain:"restaurant-system-beec1.firebaseapp.com",
      projectId:"restaurant-system-beec1",
      storageBucket:"restaurant-system-beec1.firebasestorage.app",
      messagingSenderId:"106757122327",
      appId:"1:106757122327:web:723d8dacbba3087b686f52"
    };
    const { getApps: _gApps, initializeApp: _initApp, getFirestore: _getFs } = window.__firebaseModules || {};
    const existingApps = _gApps ? _gApps() : (window.__fbApp ? [window.__fbApp] : []);
    const app = existingApps.length ? existingApps[0] : (_initApp ? _initApp(firebaseConfig) : window.__fbApp);
    const db = (_getFs ? _getFs(app) : null) || window.__fbDb;
    window.__couponDb = db;
    window.__couponDoc = doc;
    window.__couponSetDoc = setDoc;
    window.__couponDeleteDoc = deleteDoc;
    window.__couponUpdateDoc = updateDoc;
    window.__couponCollection = collection;

    window.__onSnapshot(window._sipCol(db, 'coupons'), snap => {
      window._sipCouponsCache = [];
      snap.forEach(d => window._sipCouponsCache.push({...d.data(), id: d.id}));
      renderCouponCards();
      console.log('[icon] Coupons synced from Firebase:', window._sipCouponsCache.length);
    });

    showToast(_si(48) + ' Coupons connected to cloud!','success');
  } catch(e) {
    console.error('Firebase coupon init error:', e);
    window._sipCouponsCache = JSON.parse(localStorage.getItem(window._sipKey('sip_coupons'))||'[]');
    showToast('Offline — using local coupons','warning');
  }
}

function getCoupons(){ return window._sipCouponsCache || []; }

async function saveCoupons(arr){
  window._sipCouponsCache = arr;
  if(window.__couponDb && window.__couponSetDoc){
    try {
      const writeBatch = window.__writeBatch; const doc = window.__doc;
    } catch(e){}
  }
  try{ localStorage.setItem(window._sipKey('sip_coupons'), JSON.stringify(arr)); }catch(e){}
}

async function saveSingleCouponToFirebase(coupon){
  if(window.__couponDb && window.__couponSetDoc && window.__couponDoc && window.__couponCollection){
    try {
      const taggedCoupon = Object.assign({}, coupon, { restaurantId: window._sip_restaurantId || '' });
      await window.__couponSetDoc(
        window.__couponDoc(window.__couponDb, 'coupons', coupon.id),
        taggedCoupon
      );
    } catch(e){ console.error('Firebase coupon save error:', e); }
  }
}

async function deleteCouponFromFirebase(id){
  if(window.__couponDb && window.__couponDeleteDoc && window.__couponDoc){
    try {
      await window.__couponDeleteDoc(window.__couponDoc(window.__couponDb, 'coupons', id));
    } catch(e){ console.error('Firebase coupon delete error:', e); }
  }
}
function couponTypeChange(){
  var t=document.getElementById('cp-type').value;
  document.getElementById('cp-pct-wrap').style.display=(t==='percent'||t==='both')?'':'none';
  document.getElementById('cp-flat-wrap').style.display=(t==='flat'||t==='both')?'':'none';
}
function couponOpenForm(editId){
  var fw=document.getElementById('coupon-form-wrap');
  fw.style.display='block';
  document.getElementById('coupon-form-title').textContent=editId?'Edit Coupon':'New Coupon Banao';
  fw._editId=editId||null;
  if(editId){
    var c=getCoupons().find(function(x){return x.id===editId;});
    if(!c) return;
    document.getElementById('cp-code').value=c.code||'';
    document.getElementById('cp-type').value=c.type||'percent';
    document.getElementById('cp-pct').value=c.pct||'';
    document.getElementById('cp-flat').value=c.flat||'';
    document.getElementById('cp-minorder').value=c.minorder||'';
    document.getElementById('cp-maxdisc').value=c.maxdisc||'';
    document.getElementById('cp-expiry').value=c.expiry||'';
    document.getElementById('cp-desc').value=c.desc||'';
    couponTypeChange();
  } else {
    ['cp-code','cp-pct','cp-flat','cp-minorder','cp-maxdisc','cp-expiry','cp-desc'].forEach(function(id){var el=document.getElementById(id);if(el)el.value='';});
    document.getElementById('cp-type').value='percent';
    couponTypeChange();
  }
  fw.scrollIntoView({behavior:'smooth',block:'start'});
}
function couponCloseForm(){ document.getElementById('coupon-form-wrap').style.display='none'; }
function couponSave(){
  var code=(document.getElementById('cp-code').value||'').trim().toUpperCase();
  var type=document.getElementById('cp-type').value;
  var pct=parseFloat(document.getElementById('cp-pct').value)||0;
  var flat=parseFloat(document.getElementById('cp-flat').value)||0;
  var minorder=parseFloat(document.getElementById('cp-minorder').value)||0;
  var maxdisc=parseFloat(document.getElementById('cp-maxdisc').value)||0;
  var expiry=document.getElementById('cp-expiry').value||'';
  var desc=(document.getElementById('cp-desc').value||'').trim();
  if(!code){ showToast('Please enter a coupon code!','error'); return; }
  if(type==='percent'&&pct<=0){ showToast('Enter a percentage (1-100)!','error'); return; }
  if(type==='flat'&&flat<=0){ showToast('Enter a flat amount!','error'); return; }
  if(type==='both'&&pct<=0&&flat<=0){ showToast('Enter a % or amount value!','error'); return; }
  if(minorder<=0){ showToast('Enter minimum order amount!','error'); return; }
  var arr=getCoupons();
  var fw=document.getElementById('coupon-form-wrap');
  var couponObj;
  if(fw._editId){
    var idx2=arr.findIndex(function(x){return x.id===fw._editId;});
    if(idx2>=0){
      couponObj=Object.assign({},arr[idx2],{code:code,type:type,pct:pct,flat:flat,minorder:minorder,maxdisc:maxdisc,expiry:expiry,desc:desc});
      arr[idx2]=couponObj;
    }
  } else {
    var dup=arr.find(function(x){return x.code===code;});
    if(dup){ showToast('This coupon code already exists!','error'); return; }
    couponObj={id:'cp_'+Date.now(),code:code,type:type,pct:pct,flat:flat,minorder:minorder,maxdisc:maxdisc,expiry:expiry,desc:desc,active:true,created:new Date().toLocaleDateString('en-IN')};
    arr.push(couponObj);
  }
  window._sipCouponsCache=arr;
  try{ localStorage.setItem(window._sipKey('sip_coupons'),JSON.stringify(arr)); }catch(e){}
  if(couponObj){ saveSingleCouponToFirebase(couponObj).then(function(){ showToast(_si(48) + ' Coupon saved to cloud!','success'); }).catch(function(){}); }
  couponCloseForm();
  renderCouponCards();
  showToast('Coupon saved!','success');
}
function couponDelete(id){
  if(!confirm('Ye coupon delete karna chahte ho?')) return;
  var arr=getCoupons().filter(function(x){return x.id!==id;});
  window._sipCouponsCache=arr;
  try{ localStorage.setItem(window._sipKey('sip_coupons'),JSON.stringify(arr)); }catch(e){}
  deleteCouponFromFirebase(id).then(function(){ showToast(_si(48) + ' Coupon also deleted from cloud!','info'); }).catch(function(){});
  renderCouponCards();
  showToast('Coupon deleted','info');
}
function couponToggle(id){
  var arr=getCoupons();
  var idx=arr.findIndex(function(x){return x.id===id;});
  if(idx>=0){
    arr[idx].active=!arr[idx].active;
    var updated=arr[idx];
    window._sipCouponsCache=arr;
    try{ localStorage.setItem(window._sipKey('sip_coupons'),JSON.stringify(arr)); }catch(e){}
    saveSingleCouponToFirebase(updated);
    renderCouponCards();
  }
}
function couponIsExpired(expiry){ if(!expiry) return false; return new Date(expiry)<new Date(new Date().toDateString()); }
function renderCouponCards(){
  var arr=getCoupons();
  var wrap=document.getElementById('coupon-cards');
  var empty=document.getElementById('coupon-empty');
  if(!wrap) return;
  if(!arr.length){empty.style.display='block';wrap.innerHTML='';return;}
  empty.style.display='none';
  var palettes=[
    {bg:'#1a0a2e',accent:'#7c3aed',text:'#f5f0e8'},
    {bg:'#0a1628',accent:'#1d4ed8',text:'#f5f0e8'},
    {bg:'#0a2818',accent:'#15803d',text:'#f5f0e8'},
    {bg:'#2a0a0a',accent:'#dc2626',text:'#f5f0e8'},
    {bg:'#1a1200',accent:'#b45309',text:'#f5f0e8'}
  ];
  wrap.innerHTML=arr.map(function(c,ci){
    var pal=palettes[ci%palettes.length];
    var expired=couponIsExpired(c.expiry);
    var opacity=expired?'0.55':'1';
    var status=expired?'EXPIRED':(c.active?'ACTIVE':'INACTIVE');
    var bigDisc='',subDisc='';
    if(c.type==='percent'){ bigDisc=c.pct+'%'; subDisc='OFF'; }
    else if(c.type==='flat'){ bigDisc='\u20b9'+c.flat; subDisc='FLAT OFF'; }
    else { bigDisc=c.pct+'%'; subDisc='+\u20b9'+c.flat+' OFF'; }
    var expText=c.expiry?('Expires: '+c.expiry):'No Expiry';
    var giftSvg='<svg width="52" height="52" viewBox="0 0 52 52" xmlns="http://www.w3.org/2000/svg">'
      +'<rect x="6" y="20" width="40" height="8" rx="2" fill="'+pal.text+'" opacity="0.9"/>'
      +'<rect x="10" y="28" width="32" height="18" rx="2" fill="'+pal.text+'" opacity="0.85"/>'
      +'<rect x="22" y="20" width="8" height="26" rx="1" fill="'+pal.accent+'" opacity="0.7"/>'
      +'<path d="M26 20 C26 20 18 14 20 9 C22 5 26 8 26 12 C26 8 30 5 32 9 C34 14 26 20 26 20Z" fill="'+pal.text+'"/>'
      +'</svg>';
    var bcLines='';
    for(var b=0;b<22;b++) bcLines+='<rect x="'+(b*4)+'" y="0" width="'+(b%3===0?3:b%2===0?2:1)+'" height="36" fill="'+pal.text+'" opacity="'+(0.5+Math.random()*0.5).toFixed(2)+'"/>';
    var disabledAttr=expired?' disabled':'';
    var activeLabel=c.active?'Deactivate':'Activate';
    return (
      '<div style="position:relative;display:flex;border-radius:16px;overflow:visible;box-shadow:0 8px 32px rgba(0,0,0,0.35);margin-bottom:4px;opacity:'+opacity+';transition:all 0.3s">'
      +'<div style="width:110px;min-width:110px;background:'+pal.bg+';border-radius:16px 0 0 16px;padding:16px 12px;display:flex;flex-direction:column;justify-content:space-between;position:relative">'
      +'<div style="position:absolute;top:-1px;right:-12px;width:24px;height:24px;background:#0a0a0f;border-radius:50%;z-index:2"></div>'
      +'<div style="position:absolute;bottom:-1px;right:-12px;width:24px;height:24px;background:#0a0a0f;border-radius:50%;z-index:2"></div>'
      +'<div style="position:absolute;top:12px;right:-1px;bottom:12px;width:2px;border-left:2px dashed rgba(255,255,255,0.15)"></div>'
      +'<div style="font-family:Courier New,monospace;font-size:9px;font-weight:600;color:'+pal.text+';opacity:0.9;letter-spacing:0.5px;line-height:1.5">'
      +'<div style="font-size:7px;opacity:0.55;letter-spacing:2px;margin-bottom:2px">CODE</div>'
      +'<div style="font-size:13px;letter-spacing:1px;color:'+pal.text+'">'+c.code+'</div>'
      +'</div>'
      +'<div>'
      +'<svg width="88" height="36" viewBox="0 0 88 36" xmlns="http://www.w3.org/2000/svg">'+bcLines+'</svg>'
      +'<div style="font-family:Courier New,monospace;font-size:8px;color:'+pal.text+';opacity:0.6;text-align:center;letter-spacing:2px;margin-top:2px">'+c.code+'</div>'
      +'</div>'
      +'</div>'
      +'<div style="flex:1;background:'+pal.accent+';padding:18px 20px;display:flex;align-items:center;gap:16px;position:relative;overflow:hidden">'
      +'<div style="position:absolute;right:80px;top:-30px;width:130px;height:130px;border-radius:50%;background:rgba(255,255,255,0.08)"></div>'
      +'<div style="position:absolute;right:50px;bottom:-40px;width:100px;height:100px;border-radius:50%;background:rgba(255,255,255,0.06)"></div>'
      +'<div style="flex:1;z-index:1">'
      +'<div style="font-family:Impact,Anton,sans-serif;font-size:52px;line-height:1;color:'+pal.text+';letter-spacing:-1px;text-shadow:0 2px 8px rgba(0,0,0,0.2)">'+bigDisc+'</div>'
      +'<div style="font-family:Impact,Anton,sans-serif;font-size:22px;color:'+pal.text+';letter-spacing:4px;opacity:0.95">COUPON</div>'
      +'<div style="font-family:Courier New,monospace;font-size:10px;color:'+pal.text+';opacity:0.85;margin-top:4px">'+subDisc+' &nbsp;|&nbsp; Min: \u20b9'+c.minorder.toLocaleString('en-IN')+'</div>'
      +(c.maxdisc?'<div style="font-family:Courier New,monospace;font-size:9px;color:'+pal.text+';opacity:0.7">Max Discount: \u20b9'+c.maxdisc+'</div>':'')
      +'<div style="font-family:Courier New,monospace;font-size:9px;color:'+pal.text+';opacity:0.65;margin-top:2px">'+expText+'</div>'
      +'</div>'
      +'<div style="display:flex;flex-direction:column;align-items:center;gap:10px;z-index:1">'
      +giftSvg
      +'<span style="font-family:Courier New,monospace;font-size:9px;font-weight:700;letter-spacing:2px;background:rgba(0,0,0,0.25);color:'+pal.text+';border-radius:20px;padding:3px 10px">'+status+'</span>'
      +'<div style="display:flex;flex-direction:column;gap:5px;width:100%">'
      +'<button class="btn btn-sm" onclick="couponToggle(\''+c.id+'\')"'+disabledAttr+' style="font-size:9px;background:rgba(0,0,0,0.2);color:'+pal.text+';border:1px solid rgba(255,255,255,0.3);border-radius:8px;padding:4px 10px;cursor:pointer;font-family:var(--font-ui)">'+activeLabel+'</button>'
      +'<button class="btn btn-sm" onclick="couponOpenForm(\''+c.id+'\')" style="font-size:9px;background:rgba(255,255,255,0.15);color:'+pal.text+';border:1px solid rgba(255,255,255,0.3);border-radius:8px;padding:4px 10px;cursor:pointer;font-family:var(--font-ui)">\u270f Edit</button>'
      +'<button class="btn btn-sm" onclick="couponDelete(\''+c.id+'\')" style="font-size:9px;background:rgba(0,0,0,0.25);color:#ffaaaa;border:1px solid rgba(255,100,100,0.4);border-radius:8px;padding:4px 10px;cursor:pointer;font-family:var(--font-ui)">\ud83d\uddd1 Delete</button>'
      +'</div>'
      +'</div>'
      +'</div>'
      +'</div>'
    );
  }).join('');
}
