function applyCouponToBill(){
  var code=(document.getElementById('m-coupon-input').value||'').trim().toUpperCase();
  var msg=document.getElementById('m-coupon-msg');
  var removeBtn=document.getElementById('m-coupon-remove-btn');
  if(!code){if(msg) msg.innerHTML='<span style="color:#e74c3c">Please enter a coupon code!</span>';return;}
  var c=getCoupons().find(function(x){return x.code===code;});
  if(!c){if(msg) msg.innerHTML='<span style="color:#e74c3c">\u274c Coupon nahi mila: '+code+'</span>';window._appliedCoupon=null;calcManualBill();return;}
  if(!c.active){if(msg) msg.innerHTML='<span style="color:#e74c3c">\u274c Ye coupon inactive hai</span>';window._appliedCoupon=null;calcManualBill();return;}
  if(couponIsExpired(c.expiry)){if(msg) msg.innerHTML='<span style="color:#e74c3c">\u274c Ye coupon expire ho gaya!</span>';window._appliedCoupon=null;calcManualBill();return;}
  window._appliedCoupon=c;
  if(removeBtn) removeBtn.style.display='';
  calcManualBill();
}
function removeCouponFromBill(){
  window._appliedCoupon=null;
  document.getElementById('m-coupon-input').value='';
  var msg=document.getElementById('m-coupon-msg');
  if(msg) msg.innerHTML='';
  var rb=document.getElementById('m-coupon-remove-btn');
  if(rb) rb.style.display='none';
  var cr=document.getElementById('m-coupon-disc-row');
  if(cr) cr.style.display='none';
  calcManualBill();
  showToast('Coupon removed','info');
}

