let searchIdx = -1;

function showSearchResults() {
  const inp = document.getElementById('global-search-input');
  const box = document.getElementById('global-search-results');
  if (!inp || !box) return;
  const q = inp.value.trim().toLowerCase();
  const filtered = q
    ? SEARCH_PAGES.filter(p => p.label.toLowerCase().includes(q) || p.desc.toLowerCase().includes(q))
    : SEARCH_PAGES.slice(0, 8);

  const header = `<div style="padding:9px 14px 7px;border-bottom:1px solid rgba(201,168,76,0.12);display:flex;align-items:center;justify-content:space-between;background:rgba(201,168,76,0.03)">
    <span style="font-family:var(--font-ui);font-size:9px;letter-spacing:2px;color:rgba(201,168,76,0.5);text-transform:uppercase">${q ? 'Results' : 'Quick Navigate'}</span>
    <span style="font-family:var(--font-ui);font-size:9px;color:rgba(245,240,232,0.2)">↑↓ move · Enter open · Esc close</span>
  </div>`;

  if (!filtered.length) {
    box.innerHTML = header + '<div style="padding:18px 16px;font-family:var(--font-ui);font-size:12px;color:rgba(245,240,232,0.35);text-align:center">"+'+_si(41)+'+" Koi feature nahi mila</div>';
    box.style.display = 'block';
    return;
  }
  box.innerHTML = header + filtered.map((p, i) =>
    `<div class="gs-item" data-page="${p.page}" data-idx="${i}"
      onclick="gotoPage('${p.page}')"
      onmouseover="setSearchIdx(${i})"
      style="display:flex;align-items:center;gap:12px;padding:10px 14px;cursor:pointer;transition:background 0.15s;border-bottom:1px solid rgba(255,255,255,0.03)">
      <div style="width:32px;height:32px;border-radius:8px;background:rgba(201,168,76,0.07);border:1px solid rgba(201,168,76,0.15);display:flex;align-items:center;justify-content:center;flex-shrink:0;font-size:15px">${p.icon}</div>
      <div style="flex:1;min-width:0">
        <div style="font-family:var(--font-ui);font-size:12px;font-weight:600;color:rgba(245,240,232,0.92)">${p.label}</div>
        <div style="font-family:var(--font-ui);font-size:10px;color:rgba(245,240,232,0.38);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;margin-top:1px">${p.desc}</div>
      </div>
      <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="rgba(201,168,76,0.4)" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="9 18 15 12 9 6"/></svg>
    </div>`
  ).join('') + (filtered.length >= 8 && !q ? `<div style="padding:8px 14px;font-family:var(--font-ui);font-size:10px;color:rgba(245,240,232,0.25);text-align:center;border-top:1px solid rgba(201,168,76,0.08)">Type karo aur search karo...</div>` : '');
  searchIdx = -1;
  box.style.display = 'block';
}

function hideSearchResults() {
  const box = document.getElementById('global-search-results');
  if (box) box.style.display = 'none';
  searchIdx = -1;
}

function setSearchIdx(i) {
  searchIdx = i;
  highlightSearchItem();
}

function highlightSearchItem() {
  document.querySelectorAll('.gs-item').forEach((el, i) => {
    el.style.background = i === searchIdx ? 'rgba(201,168,76,0.12)' : '';
  });
}

function gotoPage(page) {
  const navEl = document.querySelector('.nav-item[onclick*="\''+page+'\'"]');
  if (typeof showPage === 'function') showPage(page, navEl);
  const inp = document.getElementById('global-search-input');
  if (inp) inp.value = '';
  hideSearchResults();
}

function searchKeyNav(e) {
  const items = document.querySelectorAll('.gs-item');
  if (e.key === 'ArrowDown') { e.preventDefault(); searchIdx = Math.min(searchIdx+1, items.length-1); highlightSearchItem(); }
  else if (e.key === 'ArrowUp') { e.preventDefault(); searchIdx = Math.max(searchIdx-1, 0); highlightSearchItem(); }
  else if (e.key === 'Enter') {
    if (searchIdx >= 0 && items[searchIdx]) { items[searchIdx].click(); }
    else if (items.length === 1) items[0].click();
  } else if (e.key === 'Escape') {
    hideSearchResults();
    document.getElementById('global-search-input').blur();
  }
}
document.addEventListener('keydown', function(e) {
  if ((e.ctrlKey || e.metaKey) && e.key === 'k') {
    e.preventDefault();
    const inp = document.getElementById('global-search-input');
    if (inp) { inp.focus(); inp.select(); }
  }
});

