var siploraFontMap = {
  'default':  { royal:"'Cormorant Garamond',serif", body:"'Tenor Sans',sans-serif", ui:"'Montserrat',sans-serif", label:'Default' },
  'inter':    { royal:"'Inter',sans-serif",          body:"'Inter',sans-serif",      ui:"'Inter',sans-serif",      label:'Inter' },
  'systemui': { royal:"system-ui,-apple-system,sans-serif", body:"system-ui,-apple-system,sans-serif", ui:"system-ui,-apple-system,sans-serif", label:'System UI' },
  'nunito':   { royal:"'Nunito',sans-serif",         body:"'Nunito',sans-serif",     ui:"'Nunito',sans-serif",     label:'Nunito' },
  'dmsans':   { royal:"'DM Sans',sans-serif",        body:"'DM Sans',sans-serif",    ui:"'DM Sans',sans-serif",    label:'DM Sans' },
  'jakarta':  { royal:"'Plus Jakarta Sans',sans-serif", body:"'Plus Jakarta Sans',sans-serif", ui:"'Plus Jakarta Sans',sans-serif", label:'Plus Jakarta Sans' }
};
function siploraApplyFont(key, el) {
  var f = siploraFontMap[key]; if(!f) return;
  var root = document.documentElement;
  root.style.setProperty('--font-royal', f.royal);
  root.style.setProperty('--font-body',  f.body);
  root.style.setProperty('--font-ui',    f.ui);
  localStorage.setItem('siplora_font', key);
  document.querySelectorAll('.siplora-font-btn').forEach(function(b){
    b.style.background = '';
    b.style.borderColor = 'rgba(255,255,255,0.08)';
  });
  if(el){ el.style.background='rgba(99,102,241,0.15)'; el.style.borderColor='rgba(99,102,241,0.6)'; }
  var lbl = document.getElementById('siplora-font-name-display');
  if(lbl) lbl.textContent = f.label;
  if(typeof showToast==='function') showToast('Font changed: '+f.label, 'success');
}
(function(){
  var saved = localStorage.getItem('siplora_font') || 'default';
  var f = siploraFontMap[saved]; if(!f) return;
  var root = document.documentElement;
  root.style.setProperty('--font-royal', f.royal);
  root.style.setProperty('--font-body',  f.body);
  root.style.setProperty('--font-ui',    f.ui);
  document.addEventListener('DOMContentLoaded', function(){
    var btn = document.querySelector('.siplora-font-btn[data-font="'+saved+'"]');
    if(btn){ btn.style.background='rgba(99,102,241,0.15)'; btn.style.borderColor='rgba(99,102,241,0.6)'; }
    var lbl = document.getElementById('siplora-font-name-display');
    if(lbl) lbl.textContent = f.label;
  });
})();
// ── END FONT SYSTEM ──────────────────────────────────────────

var _profileOpen = false;
function toggleProfileDropdown() {
  _profileOpen = !_profileOpen;
  var dd = document.getElementById('profile-dropdown');
  var chev = document.getElementById('profile-chevron');
  if(dd){ dd.style.display = _profileOpen ? 'block' : 'none'; dd.style.animation = _profileOpen ? 'profileDropIn 0.22s cubic-bezier(0.4,0,0.2,1)' : ''; }
  if(chev) chev.style.transform = _profileOpen ? 'rotate(180deg)' : 'rotate(0deg)';
}
function closeProfileDropdown() {
  _profileOpen = false;
  var dd = document.getElementById('profile-dropdown');
  var chev = document.getElementById('profile-chevron');
  if(dd) dd.style.display = 'none';
  if(chev) chev.style.transform = 'rotate(0deg)';
}
document.addEventListener('click', function(e){
  var wrap = document.getElementById('profile-wrap');
  if(wrap && !wrap.contains(e.target)) closeProfileDropdown();
});

function siploraLogout() {
  closeProfileDropdown();
  if(confirm('Siplora se logout karna chahte ho?')) {
    showToast(_si(161) + ' Logged out! Come back soon!', 'info');
    setTimeout(function(){ location.reload(); }, 1200);
  }
}

