          + '<div style="font-family:var(--font-ui);font-size:9px;color:rgba(245,240,232,0.32);margin-top:1px;display:flex;align-items:center;gap:4px"><svg width="9" height="9" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"/><circle cx="12" cy="10" r="3"/></svg> '+cap.area+' · T'+(cap.tableFrom||'?')+'–T'+(cap.tableTo||'?')+(totalTables?' ('+totalTables+' tables)':'')+'</div>'
