          + '<div style="background:rgba(155,89,182,0.07);border:1px solid rgba(155,89,182,0.15);border-radius:8px;padding:6px 4px;text-align:center"><div style="font-family:var(--font-royal);font-size:14px;color:#9b59b6">'+billsCount+'</div><div style="font-family:var(--font-ui);font-size:7px;color:rgba(245,240,232,0.35);letter-spacing:0.5px;margin-top:1px">BILLS AAJ</div></div>'
